-- Schema for Domain: inventory | Business: Agriculture | Version: v1_ecm
-- Generated on: 2026-05-01 16:23:37

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `agriculture_ecm`.`inventory` COMMENT 'SSOT for all agricultural inventory positions across grain bins, cold storage, warehouses, and field stockpiles. Tracks commodity lots (LOT/GRN), quantities in CWT, BU, and MT, storage location assignments, FIFO/FEFO rotation, shrinkage, expiration dates (PHI), stock rotation, and WMS-driven cycle counts. Manages seed, chemical, fertilizer, and harvested commodity stock levels with SAP S/4HANA MM and Manhattan Associates WMS integration. Ensures GRN processing and inventory accuracy for supply chain continuity.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`stock_position` (
    `stock_position_id` BIGINT COMMENT 'Unique surrogate identifier for each stock position record in the agricultural inventory system. Primary key for the stock_position data product.',
    `bin_location_id` BIGINT COMMENT 'Foreign key linking to inventory.bin_location. Business justification: stock_position has storage_bin (STRING) as a denormalized WMS bin reference. Stock positions are tracked at bin level in WMS for precise inventory location. Adding bin_location_id FK links the positio',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the commodity lot or batch record (LOT/GRN) associated with this stock position, enabling FIFO/FEFO rotation, traceability, and pre-harvest interval (PHI) compliance tracking.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Stock positions are valued and reported within a legal entity (company code) for consolidated financial statements. Multi-entity agriculture operations require company code assignment on inventory pos',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Inventory valuation postings (balance sheet stock accounts) require GL account assignment per valuation class. Agriculture finance teams reconcile stock value to GL for period-close and GAAP/IFRS inve',
    `plant_id` BIGINT COMMENT 'Reference to the SAP plant (facility or farm site) under which this stock position is managed. Supports multi-site inventory visibility and plant-level reporting.',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record representing the agricultural commodity, seed, chemical, or fertilizer held in this stock position. Aligns with SAP S/4HANA MM material master.',
    `stock_material_master_id` BIGINT COMMENT 'FK to inventory.material_master',
    `storage_location_id` BIGINT COMMENT 'Reference to the storage location (grain bin, cold storage, warehouse, field stockpile) where this inventory position is held. Aligns with SAP S/4HANA MM storage location and Manhattan Associates WMS location master.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this stock position record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides the audit trail creation marker for data lineage and SOX compliance.',
    `expiration_date` DATE COMMENT 'Expiration or best-before date for this stock position. For harvested commodities, this may align with the Pre-Harvest Interval (PHI) or shelf-life date. Drives FEFO rotation, quality holds, and food safety compliance. Null for non-perishable materials.',
    `goods_receipt_date` DATE COMMENT 'Date the material was received into inventory at the storage location (GRN posting date). Used for FIFO rotation sequencing, aging analysis, and inbound supply chain performance reporting.',
    `grn_number` STRING COMMENT 'Goods Receipt Note (GRN) number from SAP S/4HANA MM or Manhattan Associates WMS that originated this stock position. Provides the inbound receiving document reference for audit and traceability.',
    `gtin` STRING COMMENT 'GS1 Global Trade Item Number (GTIN-14) identifying the agricultural product for global supply chain interoperability, retail scanning, and COOL (Country of Origin Labeling) compliance.. Valid values are `^d{14}$`',
    `is_gmo` BOOLEAN COMMENT 'Indicates whether the material in this stock position is a Genetically Modified Organism (GMO). Required for USDA NOP organic certification compliance, COOL labeling, and customer segregation requirements.',
    `is_organic_certified` BOOLEAN COMMENT 'Indicates whether the material in this stock position holds USDA National Organic Program (NOP) certification. Drives segregation requirements, premium pricing, and organic supply chain compliance.',
    `last_cycle_count_date` DATE COMMENT 'Date of the most recent WMS-driven cycle count performed for this stock position. Used to assess inventory accuracy, schedule next count, and support audit compliance for GAAP/IFRS inventory verification.',
    `last_movement_date` DATE COMMENT 'Date of the most recent inventory movement (goods receipt, goods issue, transfer, or adjustment) recorded against this stock position. Used for slow-moving and obsolete inventory identification.',
    `manufacture_date` DATE COMMENT 'Date the material in this stock position was manufactured, processed, or harvested. Used for FIFO/FEFO rotation, shelf-life calculation, and traceability under FSMA and GLOBALG.A.P. requirements.',
    `phi_days` STRING COMMENT 'Pre-Harvest Interval (PHI) in days — the minimum number of days that must elapse between the last pesticide or chemical application and harvest for this lot. Ensures Maximum Residue Limit (MRL) compliance and food safety regulatory adherence.',
    `price_variance_usd` DECIMAL(18,2) COMMENT 'Variance between the standard cost and actual purchase price for this stock position in USD. Captured at period-end for GAAP/IFRS inventory valuation adjustments and commodity price risk reporting.',
    `qty_available` DECIMAL(18,2) COMMENT 'Available-to-promise (ATP) quantity calculated as on-hand quantity minus reserved quantity in the primary unit of measure. Represents the uncommitted inventory available for new sales orders or production requirements.',
    `qty_blocked` DECIMAL(18,2) COMMENT 'Quantity of the material in blocked stock status (not available for use) in the primary unit of measure. Includes recalled, quarantined, or damaged inventory pending disposition decision.',
    `qty_in_quality_inspection` DECIMAL(18,2) COMMENT 'Quantity of the material currently held in quality inspection stock pending QM release in the primary unit of measure. Supports HACCP, FSMA, and GLOBALG.A.P. quality hold management.',
    `qty_on_hand` DECIMAL(18,2) COMMENT 'Total physical quantity of the material currently on hand at the storage location in the primary unit of measure (CWT, BU, or MT). Represents the gross inventory position before reservations or holds.',
    `qty_reserved` DECIMAL(18,2) COMMENT 'Quantity of the material reserved against open sales orders, production orders, or transfer orders in the primary unit of measure. Reduces available-to-promise (ATP) quantity for new commitments.',
    `qty_shrinkage` DECIMAL(18,2) COMMENT 'Cumulative quantity lost to shrinkage (moisture loss, spoilage, handling losses) recorded against this stock position in the primary unit of measure. Used for shrinkage analysis, COGS adjustment, and post-harvest handling performance reporting.',
    `rotation_method` STRING COMMENT 'Inventory rotation method applied to this stock position for picking and consumption sequencing. FIFO (First In First Out) and FEFO (First Expired First Out) are standard for agricultural commodities and perishables to minimize spoilage and ensure food safety compliance.. Valid values are `fifo|fefo|lifo|manual`',
    `sap_accounting_doc_number` STRING COMMENT 'SAP FI accounting document number (BELNR) generated for the inventory valuation posting associated with this stock position. Provides the audit trail reference for GAAP/IFRS financial reporting and SOX compliance.',
    `sscc` STRING COMMENT 'GS1 Serial Shipping Container Code (SSCC-18) assigned to the logistics unit (pallet, bin, container) holding this stock position. Enables RFID-based tracking and WMS integration for supply chain traceability.. Valid values are `^d{18}$`',
    `stock_status` STRING COMMENT 'Current lifecycle status of the stock position record. Active indicates normal inventory; expired indicates stock past its shelf life or PHI; recalled indicates a regulatory or quality recall event; quarantined indicates hold pending investigation; disposed indicates stock written off.. Valid values are `active|expired|recalled|quarantined|disposed`',
    `stock_type` STRING COMMENT 'SAP S/4HANA stock type classification indicating the usability of the inventory. Unrestricted stock is available for use; quality inspection stock is pending QM release; blocked stock is not available; in-transit stock is between locations; returns stock is pending disposition.. Valid values are `unrestricted|quality_inspection|blocked|in_transit|returns`',
    `total_value_usd` DECIMAL(18,2) COMMENT 'Total book value of this stock position in US dollars (USD), calculated as on-hand quantity multiplied by unit price. Used for balance sheet inventory reporting, period-end valuation snapshots, and GAAP/IFRS financial reporting.',
    `unit_price_usd` DECIMAL(18,2) COMMENT 'Inventory valuation price per primary unit of measure in US dollars (USD). For standard cost materials, this is the standard price; for moving average materials, this is the current moving average price. Used for period-end inventory valuation and COGS calculation.',
    `uom_primary` STRING COMMENT 'Primary unit of measure for quantity reporting on this stock position. Agricultural commodities use industry-standard units: CWT (Hundredweight), BU (Bushel), MT (Metric Ton). Seeds and chemicals may use KG, LB, BAG, or EA. [ENUM-REF-CANDIDATE: CWT|BU|MT|KG|LB|TON|EA|BAG — 8 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this stock position record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC), data lineage, and audit trail compliance.',
    `valuation_date` DATE COMMENT 'Date as of which the inventory valuation snapshot was captured for this stock position. Used for period-end financial reporting, GAAP/IFRS inventory valuation, and commodity position reporting.',
    `valuation_method` STRING COMMENT 'Inventory valuation method applied to this stock position. Standard cost uses a predetermined price; moving average recalculates price with each goods movement; FIFO (First In First Out) values inventory based on oldest cost layers. Supports GAAP and IFRS inventory accounting.. Valid values are `standard_cost|moving_average|fifo`',
    `wms_position_number` STRING COMMENT 'Manhattan Associates WMS internal position or license plate number for this stock position. Used for WMS-to-SAP reconciliation, cycle count management, and real-time inventory visibility.',
    CONSTRAINT pk_stock_position PRIMARY KEY(`stock_position_id`)
) COMMENT 'Core master record of current inventory positions across all agricultural storage locations (grain bins, cold storage, warehouses, field stockpiles). Tracks on-hand, reserved, and available-to-promise quantities in CWT, BU, and MT by material, commodity lot, and location. Includes stock type (unrestricted, quality inspection, blocked), valuation class, unit price, total value, and valuation method (standard cost, moving average, FIFO). Supports period-end valuation snapshots capturing valuation date, quantity, unit price, total value in USD, price variance, and SAP accounting document reference for GAAP/IFRS inventory valuation, COGS calculation, and commodity position reporting. Serves as the SSOT for real-time stock levels, inventory valuation, and period-end financial inventory reporting. Supports GS1 GTIN and SSCC identifiers for global supply chain interoperability. Integrates with SAP S/4HANA MM and Manhattan Associates WMS.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`commodity_lot` (
    `commodity_lot_id` BIGINT COMMENT 'Unique surrogate identifier for each commodity lot record in the agricultural inventory system. Primary key for the commodity_lot data product. Entity role: MASTER_RESOURCE — represents a physical lot/batch of agricultural commodity tracked through the supply chain.',
    `commodity_hedge_id` BIGINT COMMENT 'Foreign key linking to finance.commodity_hedge. Business justification: Grain lots are assigned to specific hedge contracts for physical delivery or cash settlement. Linking lot to hedge instrument supports hedge accounting designation, basis tracking, and CFTC position r',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Commodity lots must reference the commodity master for USDA grade standards, MRL thresholds, storage requirements, and exchange pricing. Grain elevator operations require this link for grade complianc',
    `crop_enterprise_budget_id` BIGINT COMMENT 'Foreign key linking to finance.crop_enterprise_budget. Business justification: Commodity lots represent actual harvested production. Linking to the enterprise budget that planned the crop enables actual vs. planned yield and cost variance analysis — a fundamental agriculture fin',
    `drought_index_id` BIGINT COMMENT 'Foreign key linking to weather.drought_index. Business justification: Drought conditions at harvest directly affect commodity lot quality — low test weight, elevated mycotoxins, and reduced grade. Grain merchandisers and insurance adjusters link lots to the drought inde',
    `gmo_declaration_id` BIGINT COMMENT 'Foreign key linking to product.gmo_declaration. Business justification: BE Act (Bioengineered Food Disclosure) requires GMO commodity lots to reference a formal GMO declaration for disclosure compliance. Linking enables export market eligibility checks (EU, China, Japan a',
    `government_program_id` BIGINT COMMENT 'Foreign key linking to finance.government_program. Business justification: Commodity lots under USDA CCC loan programs or ARC/PLC must be tracked against enrolled program records for payment calculation, compliance verification, and FSA reporting. Agriculture domain experts ',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Commodity lots are graded at elevator receipt against USDA grading standards. Linking to grading_standard enables grade compliance verification, USDA grade certificate generation, and contract settlem',
    `growing_season_id` BIGINT COMMENT 'Foreign key linking to crop.growing_season. Business justification: A commodity lot is produced in a specific growing season. Linking commodity_lot to growing_season enables grain traceability back to the originating season for crop insurance, quality reporting, and g',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Frost alerts at harvest time cause frost-damaged grain lots with reduced quality and grade. Role-prefix harvest_ distinguishes this from a storage-phase frost event. Grain quality managers and insur',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: USDA NOP requires organic commodity lots to be traceable to a valid organic certification for identity preservation and premium pricing. Linking enables certification validity checks at lot level, NOP',
    `organic_compliance_record_id` BIGINT COMMENT 'Foreign key linking to compliance.organic_compliance_record. Business justification: NOP organic certification requires each certified commodity lot to be traceable to the organic compliance record covering its production operation. The commodity_lot has is_organic_certified and organ',
    `field_id` BIGINT COMMENT 'Reference to the farm field or parcel from which this commodity lot was harvested, enabling farm-to-table traceability per FSMA Section 204 and GLOBALG.A.P. Traceability Standard. Links to field/parcel master data managed in John Deere Operations Center and Esri ArcGIS.',
    `management_zone_id` BIGINT COMMENT 'Foreign key linking to land.management_zone. Business justification: Sub-field grain traceability for identity-preserved and premium grain programs: commodity lots harvested from specific management zones (high/low productivity) are segregated and priced differently. A',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Hail and flood precipitation events directly damage commodity lots at harvest or in storage, triggering insurance claims and quality downgrades. Grain merchandisers and insurance adjusters require thi',
    `variety_id` BIGINT COMMENT 'Foreign key linking to research.variety. Business justification: Seed/grain variety traceability: a commodity_lot of seed or harvested grain corresponds to a specific research variety. This FK enables variety performance tracking from inventory, IP protection compl',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Contract position management and FSMA traceability: commodity lots are procured or harvested against forward sales contracts in grain trading. This FK supports contract fulfillment tracking, basis con',
    `seed_variety_id` BIGINT COMMENT 'Foreign key linking to product.seed_variety. Business justification: Seed commodity lots require variety-level traceability for seed certification compliance, germination rate tracking, and replanting eligibility decisions. Seed dealers and farm operations must link se',
    `storage_location_id` BIGINT COMMENT 'Reference to the current storage location (grain bin, cold storage unit, warehouse bay, or field stockpile) where this commodity lot is physically stored. Managed by Manhattan Associates WMS and SAP S/4HANA MM storage location master.',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: USDA NOP and ISCC chain-of-custody compliance requires each commodity lot to reference its governing sustainability/organic certification. Enables organic lot traceability audits, certificate validati',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: In agriculture grain and input trading, commodity lots are received against specific vendor contracts. Linking commodity_lot to vendor_contract enables contract volume utilization tracking, contracted',
    `vendor_id` BIGINT COMMENT 'Reference to the supplier or grower who delivered this commodity lot. Required for procurement traceability, COOL (Country of Origin Labeling) compliance, and vendor quality scorecarding in SAP S/4HANA MM.',
    `best_before_date` DATE COMMENT 'The best-before date for this commodity lot, after which quality may degrade but the product may still be safe for consumption. Used for FEFO (First Expired First Out) rotation logic in WMS and for customer shipment eligibility checks. Distinct from expiration_date which represents a hard safety cutoff.',
    `coa_number` STRING COMMENT 'Reference number of the Certificate of Analysis (COA) issued for this commodity lot by an accredited laboratory, documenting quality test results including moisture, protein, mycotoxins, pesticide residues, and heavy metals. Required for customer shipment documentation and regulatory compliance.',
    `country_of_origin` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code indicating the country where this commodity was produced or harvested. Required for USDA Country of Origin Labeling (COOL) compliance, export documentation (BOL, AWB), and customs declarations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this commodity lot record was first created in the system, typically upon GRN posting in SAP S/4HANA MM or inbound receipt confirmation in Manhattan Associates WMS. Serves as the audit trail anchor for record lineage and FSMA traceability documentation.',
    `days_to_expiry` STRING COMMENT 'Number of days remaining until the lots expiration_date as of the last inventory snapshot date. Used for FEFO prioritization alerts, customer minimum shelf-life requirement checks, and proactive disposition planning. Negative values indicate the lot is past expiration.',
    `disposition_action` STRING COMMENT 'Prescribed disposition action for this commodity lot, particularly for lots in quarantine, hold, or expired status. Determined by quality management review in SAP QM. Drives downstream WMS and logistics workflows for lot resolution.. Valid values are `release|rework|destroy|return_to_supplier|donate|regrade`',
    `expiration_date` DATE COMMENT 'Hard expiration date for this commodity lot, after which the product must not be sold or used for food/feed purposes. Triggers automatic lot status change to expired in WMS and SAP MM. Used as the primary FEFO sort key for lot selection in Manhattan Associates WMS pick logic.',
    `gmo_status` STRING COMMENT 'GMO status of the commodity lot indicating whether the crop is genetically modified, non-GMO, or identity-preserved (IP) non-GMO with documented segregation. Required for export documentation, customer labeling compliance, and USDA NOP organic certification. Identity-preserved lots require full chain-of-custody documentation.. Valid values are `gmo|non_gmo|identity_preserved|unknown`',
    `grade` STRING COMMENT 'Official USDA grade designation assigned to this commodity lot based on moisture, test weight, damaged kernels, foreign material, and other quality factors per FGIS Official Grain Standards. Grade determines market price, storage eligibility, and end-use suitability.. Valid values are `US No.1|US No.2|US No.3|US No.4|US No.5|Sample Grade`',
    `grn_number` STRING COMMENT 'Goods Receipt Note reference number generated in SAP S/4HANA MM upon physical receipt of the commodity lot at a storage facility. Links the lot to the inbound delivery and purchase order for procurement traceability and inventory valuation.. Valid values are `^GRN-[A-Z0-9]{4,20}$`',
    `gs1_sscc` STRING COMMENT '18-digit GS1 Serial Shipping Container Code assigned to the pallet or container carrying this commodity lot, enabling RFID and barcode scanning for pallet-level traceability from farm to table. Supports EDI and WMS integration with Manhattan Associates.. Valid values are `^[0-9]{18}$`',
    `hold_reason` STRING COMMENT 'Free-text description of the reason this commodity lot has been placed on hold or quarantine status. Examples include: failed mycotoxin test, suspected pesticide contamination, pending COA, supplier dispute, or regulatory investigation. Required when lot_status is hold or quarantine.',
    `is_organic_certified` BOOLEAN COMMENT 'Indicates whether this commodity lot is certified organic under the USDA National Organic Program (NOP) or equivalent international organic certification. Organic-certified lots require strict segregation from conventional lots and carry premium pricing. Must be supported by a valid Certificate of Analysis (COA) from an accredited certifier.',
    `last_cycle_count_date` DATE COMMENT 'Date of the most recent WMS-driven cycle count or physical inventory verification for this commodity lot. Used to assess inventory accuracy, trigger recount workflows, and support FSMA traceability audit readiness. Managed through Manhattan Associates WMS cycle count module.',
    `lot_number` STRING COMMENT 'Externally-known alphanumeric lot identifier assigned at receipt or production, used for traceability across the agricultural supply chain. Corresponds to SAP MM batch number and Manhattan WMS lot number. Serves as the primary business-facing identifier for FIFO/FEFO rotation, recall management, and FSMA Section 204 traceability.. Valid values are `^LOT-[A-Z0-9]{2,20}$`',
    `lot_status` STRING COMMENT 'Current lifecycle status of the commodity lot within the inventory management system. Drives FIFO/FEFO rotation logic, WMS pick eligibility, and disposition workflows. quarantine and hold statuses block lot from fulfillment until quality release. [ENUM-REF-CANDIDATE: available|quarantine|hold|released|consumed|expired|disposed — promote to reference product]',
    `manufacture_date` DATE COMMENT 'Date on which this commodity lot was produced, processed, or packaged. For harvested commodities, this is the harvest date. For processed products (feed, flour, oil), this is the processing date. Used as the anchor date for shelf-life and expiration calculations.',
    `moisture_content_pct` DECIMAL(18,2) COMMENT 'Moisture content of the commodity lot expressed as a percentage of total weight, measured at receipt or post-drying. Critical quality parameter for grain grading, shrinkage calculation, storage eligibility, and price discounting. USDA standard moisture for corn is 15.5%, wheat 13.5%, soybeans 13%.',
    `quantity_bu` DECIMAL(18,2) COMMENT 'Current on-hand quantity of the commodity lot expressed in bushels (BU), the standard US grain trade unit of measure. Used for grain elevator accounting, CBOT futures hedging, and WASDE supply reporting. One bushel equals 56 lbs for corn/sorghum, 60 lbs for wheat/soybeans.',
    `quantity_cwt` DECIMAL(18,2) COMMENT 'Current on-hand quantity of the commodity lot expressed in hundredweight (CWT = 100 lbs), commonly used for livestock feed, cotton, and specialty crop pricing and billing. Supports SAP MM inventory valuation in CWT-denominated contracts.',
    `quantity_mt` DECIMAL(18,2) COMMENT 'Current on-hand quantity of the commodity lot expressed in metric tons (MT), the standard international trade unit. Used for export documentation, CIF/FOB contracts, and Codex Alimentarius reporting. Derived from BU quantity using commodity-specific conversion factors but stored for operational efficiency.',
    `receipt_date` DATE COMMENT 'Date on which this commodity lot was physically received at the storage facility and the GRN was posted in SAP S/4HANA MM. Serves as the FIFO anchor date for first-in-first-out rotation logic and the start of the storage tenure calculation.',
    `received_quantity_bu` DECIMAL(18,2) COMMENT 'Original quantity of this commodity lot at the time of GRN receipt, expressed in bushels. Preserved as the immutable receipt quantity for shrinkage calculation, inventory reconciliation, and audit trail. Distinct from quantity_bu which reflects current on-hand quantity after consumption and adjustments.',
    `rotation_method` STRING COMMENT 'Inventory rotation method applied to this commodity lot for pick sequencing in Manhattan Associates WMS. FIFO (First In First Out) is standard for grain; FEFO (First Expired First Out) is required for perishable produce and feed with expiration dates. FEFO_FIFO applies FEFO when expiration dates exist, otherwise FIFO.. Valid values are `FIFO|FEFO|LIFO|FEFO_FIFO`',
    `shrinkage_pct` DECIMAL(18,2) COMMENT 'Percentage of quantity lost from this lot due to moisture evaporation, handling losses, or storage shrink since receipt. Calculated as (received_quantity - current_quantity) / received_quantity * 100. Used for inventory valuation adjustments, storage contract billing, and loss reporting.',
    `storage_type` STRING COMMENT 'Type of storage facility where this commodity lot is currently held. Determines applicable storage conditions, monitoring requirements, and handling procedures. Cold storage lots require temperature and humidity monitoring per FDA FSMA Produce Safety Rule.. Valid values are `grain_bin|cold_storage|warehouse|field_stockpile|silo|flat_storage`',
    `test_weight_lbs_bu` DECIMAL(18,2) COMMENT 'Test weight of the commodity lot measured in pounds per bushel (lbs/bu), a key grain quality indicator reflecting kernel density and market grade. Minimum test weights per USDA GIPSA: corn 56 lbs/bu (No.1), wheat 60 lbs/bu (No.1), soybeans 56 lbs/bu (No.1). Affects price premiums and discounts.',
    `uom_primary` STRING COMMENT 'The primary unit of measure used for inventory management and reporting of this commodity lot (e.g., BU for grain, MT for export commodities, CWT for feed). Aligns with SAP MM base unit of measure configuration and Manhattan WMS UOM settings. [ENUM-REF-CANDIDATE: BU|MT|CWT|LB|KG|TON|BAG|UNIT — 8 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this commodity lot record, including quantity adjustments, status changes, quality updates, or location transfers. Supports audit trail requirements and Silver Layer delta processing in the Databricks Lakehouse.',
    CONSTRAINT pk_commodity_lot PRIMARY KEY(`commodity_lot_id`)
) COMMENT 'Master record for each commodity lot (LOT/GRN) tracked through the agricultural supply chain. Captures lot number, GRN reference, GS1 SSCC for pallet/container-level tracking, commodity type (grain, produce, feed), crop year, origin field, GMO status, organic certification flag per USDA NOP, grade, moisture content, test weight, and expiration management (PHI date, best-before date, manufacture date, expiration status, days to expiry, disposition action). Supports FIFO/FEFO rotation logic with expiration-driven lot selection, quarantine/hold management, and full traceability from farm to table per FSMA Section 204, EU General Food Law Regulation 178/2002, and Codex Alimentarius traceability guidelines.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`storage_location` (
    `storage_location_id` BIGINT COMMENT 'Unique surrogate identifier for each physical storage location record in the inventory master. Primary key for the storage_location data product.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Storage locations belong to a legal entity for financial reporting, asset ownership, and regulatory licensing. Multi-entity agriculture operations require company code assignment on storage locations ',
    `facility_id` BIGINT COMMENT 'FK to supply.facility',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: Farm-unit-level storage capacity planning and USDA/FSA reporting: operators must know total storage capacity per farm unit for harvest logistics, crop insurance unit assignments, and FSA farm records.',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Grain elevators, warehouses, and storage facilities are major capitalized fixed assets. Linking storage_location to fixed_asset supports depreciation cost allocation to inventory operations, asset imp',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to land.parcel. Business justification: On-farm storage structures (grain bins, silos) are assessed as improvements on a specific parcel for property tax, crop insurance, and FSA farm records. Agriculture domain experts expect storage facil',
    `station_id` BIGINT COMMENT 'Foreign key linking to weather.weather_station. Business justification: Grain storage managers use the assigned weather stations temperature, humidity, and precipitation data to make aeration, drying, and fumigation decisions — a core grain storage condition monitoring',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Storage locations are assigned to weather zones for USDA crop insurance eligibility, climate risk classification, and disaster reporting. Agriculture operations require this link for insurance underwr',
    `address_line1` STRING COMMENT 'Primary street address of the storage facility. Used for logistics, carrier routing, regulatory filings, and emergency services. Classified as confidential organizational address data.',
    `capacity_bu` DECIMAL(18,2) COMMENT 'Maximum rated storage capacity of this location expressed in Bushels (BU), the standard volumetric unit for grain commodities (corn, soybeans, wheat). Used for grain bin and elevator capacity planning and USDA reporting.',
    `capacity_cwt` DECIMAL(18,2) COMMENT 'Maximum rated storage capacity of this location expressed in Hundredweight (CWT), a unit commonly used for livestock feed, fertilizer, and certain commodity pricing in North American agricultural markets.',
    `capacity_mt` DECIMAL(18,2) COMMENT 'Maximum rated storage capacity of this location expressed in Metric Tons (MT). Used for international trade reporting, export documentation, and compliance with Codex Alimentarius and EU food safety standards.',
    `city` STRING COMMENT 'City in which the storage facility is located. Used for regional reporting, logistics zone assignment, and regulatory jurisdiction determination.',
    `commissioning_date` DATE COMMENT 'Date on which this storage location was officially commissioned and made available for operational use. Marks the start of the locations active lifecycle for asset management and depreciation purposes.',
    `commodity_class` STRING COMMENT 'Primary commodity classification that this storage location is designed or certified to store. Drives applicable regulatory requirements, handling procedures, and inventory segregation rules. [ENUM-REF-CANDIDATE: grain|oilseed|produce|livestock_feed|seed|chemical|fertilizer|mixed — promote to reference product]',
    `country_code` STRING COMMENT 'Three-letter ISO 3166-1 Alpha-3 country code for the country where the storage location is situated (e.g., USA, CAN, BRA). Used for Country of Origin Labeling (COOL) compliance and international trade documentation.. Valid values are `^[A-Z]{3}$`',
    `cycle_count_frequency` STRING COMMENT 'Scheduled frequency for WMS-driven physical inventory cycle counts at this storage location. Determines how often inventory accuracy is verified against system records to support FIFO/FEFO compliance and shrinkage detection.. Valid values are `daily|weekly|monthly|quarterly|annual|on_demand`',
    `decommission_date` DATE COMMENT 'Date on which this storage location was or is scheduled to be permanently decommissioned and removed from active inventory operations. Nullable for active locations.',
    `fda_registration_number` STRING COMMENT 'FDA facility registration number assigned under the Food Safety Modernization Act (FSMA) for food storage facilities. Required for facilities storing human or animal food commodities subject to FDA jurisdiction.',
    `fifo_fefo_method` STRING COMMENT 'Inventory rotation method enforced for this storage location. FIFO (First-In-First-Out) is standard for grain; FEFO (First-Expired-First-Out) is required for perishables and chemicals with Pre-Harvest Interval (PHI) constraints. Drives WMS pick sequencing.. Valid values are `FIFO|FEFO|LIFO|manual`',
    `food_safety_certification` STRING COMMENT 'Primary food safety certification standard held by this storage facility (e.g., Safe Quality Food (SQF), British Retail Consortium (BRC), International Featured Standards (IFS), ISO 22000, HACCP). Drives customer eligibility and audit requirements. [ENUM-REF-CANDIDATE: SQF|BRC|IFS|GLOBALG.A.P.|ISO22000|HACCP|none — promote to reference product]. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|ISO22000|HACCP|none`',
    `gln` STRING COMMENT 'GS1 Global Location Number (GLN) — a 13-digit internationally standardized identifier uniquely identifying this physical storage location within the global supply chain. Used for Electronic Data Interchange (EDI), traceability, and GLOBALG.A.P. compliance.. Valid values are `^[0-9]{13}$`',
    `gmo_segregation_required` BOOLEAN COMMENT 'Indicates whether this storage location is designated for Genetically Modified Organism (GMO)-segregated storage, requiring physical separation from non-GMO commodities. True = GMO segregation enforced; False = no segregation requirement.',
    `humidity_controlled` BOOLEAN COMMENT 'Indicates whether this storage location has active humidity control systems. True = humidity-controlled; False = ambient humidity. Critical for seed storage, dried commodities, and chemical storage.',
    `last_cycle_count_date` DATE COMMENT 'Date of the most recently completed physical inventory cycle count at this storage location. Used to track compliance with cycle count schedules and identify locations overdue for verification.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent regulatory or food safety inspection conducted at this storage location by USDA, FDA, or a third-party auditor. Used for compliance tracking and audit readiness.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate (decimal degrees, WGS84) of the storage location as captured via GPS/GIS. Used for Esri ArcGIS spatial analysis, logistics routing, and emergency response planning.',
    `location_code` STRING COMMENT 'Alphanumeric business identifier for the storage location as defined in the Warehouse Management System (WMS) and SAP S/4HANA MM module. Used for operational referencing, labeling, and system integration across Manhattan Associates WMS and SAP.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `location_status` STRING COMMENT 'Current operational lifecycle status of the storage location. Controls whether inventory can be received, stored, or dispatched from this location. quarantined indicates a hold pending quality or regulatory inspection.. Valid values are `active|inactive|under_maintenance|quarantined|decommissioned|pending_inspection`',
    `location_type` STRING COMMENT 'Classification of the physical storage location by its structural and functional type. Drives applicable capacity units, temperature controls, and regulatory compliance requirements. [ENUM-REF-CANDIDATE: grain_bin|cold_storage|dry_warehouse|refrigerated_warehouse|field_stockpile|chemical_storage|seed_vault|fertilizer_bay — promote to reference product]',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate (decimal degrees, WGS84) of the storage location as captured via GPS/GIS. Used for Esri ArcGIS spatial analysis, logistics routing, and supply chain mapping.',
    `max_humidity_pct` DECIMAL(18,2) COMMENT 'Maximum relative humidity level (%) designed or required for this storage location. Exceeding this threshold triggers alerts for potential spoilage, mycotoxin risk, or chemical degradation.',
    `max_temperature_c` DECIMAL(18,2) COMMENT 'Maximum allowable or designed operating temperature for this storage location in degrees Celsius. Defines the upper thermal boundary for safe storage of perishable commodities, chemicals, and seeds.',
    `min_humidity_pct` DECIMAL(18,2) COMMENT 'Minimum relative humidity level (%) designed or required for this storage location. Controls moisture conditions to prevent commodity degradation, mold growth, and seed viability loss.',
    `min_temperature_c` DECIMAL(18,2) COMMENT 'Minimum allowable or designed operating temperature for this storage location in degrees Celsius. Critical for cold storage, refrigerated warehouses, and seed vaults to maintain product viability and food safety compliance.',
    `next_inspection_due_date` DATE COMMENT 'Scheduled date for the next mandatory regulatory or food safety inspection at this storage location. Drives compliance calendar management and proactive audit preparation.',
    `notes` STRING COMMENT 'Free-text operational notes or remarks about this storage location, including special handling instructions, known constraints, maintenance history summaries, or regulatory conditions. Used by warehouse operations and compliance teams.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether this storage location holds USDA National Organic Program (NOP) certification, permitting storage of certified organic commodities. True = organic certified; False = not certified for organic storage.',
    `plant_code` STRING COMMENT 'Four-character SAP S/4HANA plant code to which this storage location belongs. A plant represents a manufacturing or distribution facility in SAP MM. Required for inventory valuation and supply chain planning.. Valid values are `^[A-Z0-9]{4}$`',
    `postal_code` STRING COMMENT 'Postal or ZIP code of the storage facility address. Used for logistics carrier rate determination, regional analytics, and regulatory jurisdiction mapping. Classified as confidential organizational address data.',
    `sap_storage_location_code` STRING COMMENT 'Four-character SAP S/4HANA MM storage location code (Lagerort) that uniquely identifies this location within a SAP plant. Used for inventory postings, Goods Receipt Note (GRN) processing, and material movements in SAP.. Valid values are `^[A-Z0-9]{4}$`',
    `state_province` STRING COMMENT 'Two or three-character state or province code where the storage facility is located (e.g., IA for Iowa, IL for Illinois). Used for USDA state-level reporting, tax jurisdiction, and regulatory compliance.. Valid values are `^[A-Z]{2,3}$`',
    `temperature_controlled` BOOLEAN COMMENT 'Indicates whether this storage location has active temperature control systems (refrigeration, heating, or climate control). True = temperature-controlled environment; False = ambient/uncontrolled temperature.',
    `usda_license_number` STRING COMMENT 'USDA Warehouse Act license number issued to this storage facility, required for federally licensed grain warehouses storing commodities under USDA oversight. Mandatory for issuing warehouse receipts and participating in USDA loan programs.',
    `wms_zone_code` STRING COMMENT 'Zone assignment code within the Manhattan Associates Warehouse Management System (WMS) that groups storage locations for pick/put-away routing, cycle counting, and labor management. Aligns with WMS zone master configuration.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    CONSTRAINT pk_storage_location PRIMARY KEY(`storage_location_id`)
) COMMENT 'Master record for all physical storage locations including grain bins, cold storage units, refrigerated warehouses, dry warehouses, and field stockpile areas. Captures location code, GS1 GLN (Global Location Number), facility name, storage type, capacity in BU/MT/CWT, temperature range, humidity controls, GIS coordinates, WMS zone assignment, and regulatory compliance certifications (USDA, FDA, EU food safety). Integrates with Manhattan Associates WMS location master.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`material_master` (
    `material_master_id` BIGINT COMMENT 'Unique surrogate identifier for each material master record in the Databricks Silver Layer. Primary key for the material_master data product. Role: MASTER_RESOURCE.',
    `chemical_compliance_id` BIGINT COMMENT 'Foreign key linking to procurement.chemical_compliance. Business justification: Agriculture material masters for agrochemicals carry EPA registration, MRL limits, and compliance data that is authoritatively owned by chemical_compliance. This link enforces 3NF, enables regulatory ',
    `emission_factor_id` BIGINT COMMENT 'Foreign key linking to sustainability.emission_factor. Business justification: Each agricultural input material (nitrogen fertilizer, diesel, agrochemical) has a specific GHG emission factor (IPCC tier 1/2) used for scope 1 and scope 3 category 1 calculations. Linking material_m',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Material master valuation class determines the GL account for all inventory postings (GR, GI, transfers). Direct FK replaces the denormalized inventory_valuation_class and supports automated GL accoun',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Material master records for commodities specify the applicable USDA grading standard for procurement specifications and quality management. This enables automated grade compliance checking during good',
    `input_catalog_id` BIGINT COMMENT 'Foreign key linking to procurement.input_catalog. Business justification: In agriculture, the approved input catalog drives material master creation — every inventory material for seeds, chemicals, and fertilizers originates from a catalog-approved input. This link enables ',
    `master_id` BIGINT COMMENT 'Foreign key linking to product.product_master. Business justification: SAP material master records are created from product catalog entries. This link enables product lifecycle management, cost rollup to product catalog, and procurement planning. Agriculture ERP implemen',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: Material master stores static MRL values (mrl_limit_eu, mrl_limit_codex) that become stale as regulations change. Linking to mrl_threshold enables dynamic compliance checking for export market eligibi',
    `variety_id` BIGINT COMMENT 'Foreign key linking to research.variety. Business justification: Seed catalog management: a material_master record for seed products corresponds to a specific research variety. This FK connects commercial seed SKUs to their research variety profiles for trait infor',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: Material master defines certification requirements at the material/SKU level (e.g., this fertilizer must be OMRI-listed, this grain must be ISCC-certified). Links material procurement rules to the aut',
    `active_ingredient` STRING COMMENT 'The primary active ingredient (AI) name and concentration for crop protection chemicals (herbicides, insecticides, fungicides). Required for EPA registration compliance, MRL calculations, and SDS documentation. Example: Glyphosate 41%. Null for non-chemical materials.',
    `base_uom` STRING COMMENT 'The primary unit of measure (UOM) in which the material is managed in inventory (SAP MEINS). Agricultural materials use industry-standard units: BU (Bushel), CWT (Hundredweight), MT (Metric Ton), KG (Kilogram), GAL (Gallon). Drives quantity calculations across procurement, WMS, and sales. [ENUM-REF-CANDIDATE: BU|CWT|MT|KG|LB|L|GAL|EA|BAG|TON — 10 candidates stripped; promote to reference product]',
    `commodity_class` STRING COMMENT 'Agricultural commodity classification code aligned with USDA and CME Group commodity designations (e.g., CORN, SOYBEAN, WHEAT, COTTON, ANHYDROUS_AMMONIA). Used for WASDE reporting, market price linkage, and supply chain analytics.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the material master record was first created in the source system (SAP S/4HANA MM). Used for audit trail, data lineage, and SOX compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `fifo_fefo_indicator` STRING COMMENT 'Inventory rotation strategy applied to this material in WMS (Manhattan Associates). FIFO (First In First Out) for commodities without expiry; FEFO (First Expired First Out) for perishables, seeds, and chemicals with shelf life. Drives pick sequencing and stock rotation compliance.. Valid values are `FIFO|FEFO|LIFO|manual`',
    `gmo_indicator` BOOLEAN COMMENT 'Indicates whether the material is derived from or contains Genetically Modified Organisms (GMO). Required for USDA NOP organic certification exclusion, EU import labeling (Regulation EC 1829/2003), and customer COA documentation. True = GMO material; False = non-GMO.',
    `gtin` STRING COMMENT 'GS1 Global Trade Item Number (GTIN-8, GTIN-12, GTIN-13, or GTIN-14) for the material. Enables barcode scanning, EDI transactions, and global supply chain traceability. Used in Manhattan Associates WMS for receiving and shipping verification.. Valid values are `^d{8}(d{4,6})?$`',
    `hazmat_class` STRING COMMENT 'DOT/IATA hazardous materials classification code for transport and storage compliance. Drives storage segregation rules in WMS, TMS routing restrictions, and BOL documentation. Examples: Class 3 (flammable liquids), Class 6 (toxic substances). non_hazmat for non-regulated materials. [ENUM-REF-CANDIDATE: 1|2|3|4|5|6|8|9|non_hazmat — 9 candidates stripped; promote to reference product]',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the material master record in the source system. Used for incremental data loading, change data capture (CDC) in the Databricks Silver Layer, and audit compliance.',
    `lifecycle_status` STRING COMMENT 'Current lifecycle state of the material master record in SAP (MMSTA / MSTAE). Controls whether the material can be procured, used in production, or sold. blocked prevents new transactions; discontinued signals end-of-life for inventory drawdown.. Valid values are `active|blocked|discontinued|in_review|obsolete|pending_approval`',
    `lot_management_indicator` BOOLEAN COMMENT 'Indicates whether this material is managed at the lot/batch level (SAP XCHPF). True = batch-managed (LOT/GRN tracking required for traceability). Critical for FSMA traceability, HACCP lot recall capability, and FEFO rotation in WMS. Seeds, chemicals, and harvested commodities are typically batch-managed.',
    `material_group` STRING COMMENT 'SAP material group code (MATKL) used to classify materials for procurement, reporting, and spend analytics. Examples: SEED-CORN, FERT-NPK, CHEM-HERB. Enables category management and supplier segmentation.. Valid values are `^[A-Z0-9]{1,9}$`',
    `material_name` STRING COMMENT 'Human-readable short description or name of the material (e.g., Urea 46-0-0 Fertilizer, Glyphosate 41% Herbicide, Yellow Corn #2). Corresponds to SAP MAKTX (material description). Used in inventory reports, purchase orders, and warehouse labels.',
    `material_type` STRING COMMENT 'High-level classification of the material aligned with SAP material type (MTART). Drives inventory valuation, procurement, and storage rules. [ENUM-REF-CANDIDATE: seed|fertilizer|crop_protection|feed_ingredient|harvested_commodity|packaging|equipment_part|other — promote to reference product]',
    `npk_nitrogen_pct` DECIMAL(18,2) COMMENT 'Nitrogen (N) content percentage in fertilizer materials, expressed as percentage by weight. Part of the NPK (Nitrogen-Phosphorus-Potassium) nutrient analysis required for fertilizer labeling compliance and agronomic application rate calculations. Null for non-fertilizer materials.',
    `npk_phosphorus_pct` DECIMAL(18,2) COMMENT 'Phosphorus (P2O5) content percentage in fertilizer materials, expressed as percentage by weight. Part of the NPK nutrient analysis required for fertilizer labeling and variable rate application (VRA) prescription planning. Null for non-fertilizer materials.',
    `npk_potassium_pct` DECIMAL(18,2) COMMENT 'Potassium (K2O) content percentage in fertilizer materials, expressed as percentage by weight. Part of the NPK nutrient analysis required for fertilizer labeling and soil management planning. Null for non-fertilizer materials.',
    `order_uom` STRING COMMENT 'The unit of measure used when ordering this material from suppliers (SAP BESTELLEINHEIT). May differ from base UOM (e.g., ordered in BAG but managed in KG). Critical for purchase order creation and GRN processing in SAP MM. [ENUM-REF-CANDIDATE: BU|CWT|MT|KG|LB|L|GAL|EA|BAG|TON — 10 candidates stripped; promote to reference product]',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether the material holds USDA National Organic Program (NOP) certification or equivalent international organic certification. Drives segregation requirements in storage, separate inventory pools, and premium pricing in sales contracts.',
    `phi_days` STRING COMMENT 'Pre-Harvest Interval (PHI) in days — the minimum number of days that must elapse between the last application of a crop protection chemical and harvest, as mandated by EPA Worker Protection Standard (WPS). Critical for FSMA compliance and food safety scheduling. Null for non-chemical materials.',
    `plu_code` STRING COMMENT 'IFPS Price Look-Up (PLU) code assigned to fresh produce and bulk agricultural commodities for retail checkout identification. Distinguishes conventional, organic, and GMO produce at point of sale.. Valid values are `^d{4,5}$`',
    `price_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the standard price (e.g., USD, EUR, BRL). Required for multi-currency operations in international agricultural trade and IFRS financial reporting.. Valid values are `^[A-Z]{3}$`',
    `procurement_type` STRING COMMENT 'SAP procurement type (BESKZ) indicating whether the material is externally procured, produced in-house, or both. Drives MRP (Material Requirements Planning) logic in SAP PP and purchasing strategy in SAP MM.. Valid values are `external|in_house|both`',
    `rei_hours` STRING COMMENT 'Restricted Entry Interval (REI) in hours — the minimum time workers must wait before re-entering a treated field after pesticide application, per EPA Worker Protection Standard (WPS). Required for OSHA and EPA compliance, field scheduling, and worker safety documentation.',
    `sap_material_number` STRING COMMENT 'The unique material number assigned in SAP S/4HANA MM module (MATNR field). Serves as the primary business identifier linking this record to the operational ERP system. Used for procurement, inventory management, and production planning transactions.. Valid values are `^[A-Z0-9-]{1,40}$`',
    `sds_reference` STRING COMMENT 'Document reference number or URL for the Safety Data Sheet (SDS) associated with hazardous materials (chemicals, fertilizers). Required under OSHA Hazard Communication Standard (HazCom) 29 CFR 1910.1200 and GHS. Enables worker safety compliance and emergency response.',
    `shelf_life_days` STRING COMMENT 'Standard shelf life of the material in days from the date of manufacture or harvest. Used to calculate expiration dates for FEFO (First Expired First Out) inventory rotation, WMS lot management, and food safety compliance. Drives PHI scheduling for crop protection chemicals.',
    `sku` STRING COMMENT 'Internal Stock Keeping Unit (SKU) code used in warehouse management and inventory control systems (Manhattan Associates WMS). Unique identifier for a specific material-packaging-size combination within the distribution network.. Valid values are `^[A-Z0-9-]{1,30}$`',
    `sscc_prefix` STRING COMMENT 'GS1 company prefix used to generate Serial Shipping Container Codes (SSCC-18) for pallet and container tracking of this material. Enables RFID-based pallet tracking and ASN (Advance Ship Notice) generation in WMS and TMS.. Valid values are `^d{7}$`',
    `standard_price` DECIMAL(18,2) COMMENT 'Standard or moving average price per base unit of measure for inventory valuation in SAP MM (STPRS/VERPR). Used for COGS calculation, purchase price variance (PPV) analysis, and financial reporting under IFRS IAS 2 and GAAP ASC 330. Classified confidential as it reflects internal cost strategy.',
    `storage_humidity_max_pct` DECIMAL(18,2) COMMENT 'Maximum allowable relative humidity percentage for storage of this material. Critical for grain storage (prevents mold/mycotoxin development), seed viability, and chemical stability. Used in grain bin and warehouse environmental monitoring via IoT sensors.',
    `storage_temp_max_c` DECIMAL(18,2) COMMENT 'Maximum allowable storage temperature in degrees Celsius for this material. Used alongside minimum temperature to define the acceptable storage temperature range for WMS slot assignment, cold chain compliance, and HACCP CCP monitoring.',
    `storage_temp_min_c` DECIMAL(18,2) COMMENT 'Minimum allowable storage temperature in degrees Celsius for this material. Drives cold storage assignment in WMS, temperature monitoring alerts via IoT sensors, and HACCP critical control point (CCP) compliance for food safety. Critical for seeds, biologicals, and perishable commodities.',
    `upc_code` STRING COMMENT '12-digit Universal Product Code (UPC-A) for retail-facing materials. Used for point-of-sale scanning, COOL (Country of Origin Labeling) compliance, and retail customer EDI. Aligns with GS1 US standards.. Valid values are `^d{12}$`',
    CONSTRAINT pk_material_master PRIMARY KEY(`material_master_id`)
) COMMENT 'SSOT for all inventory-managed materials including seeds, fertilizers (NPK), crop protection chemicals (AI/MRL-classified), feed ingredients, harvested commodities, and packaging materials. Captures SAP material number, SKU, GS1 GTIN, SSCC for pallet/container tracking, UPC/PLU codes, unit of measure (BU, CWT, MT, KG), material group, commodity class, GMO indicator, SDS reference, MRL limits per EU Regulation 396/2005 and Codex Alimentarius standards, REI/PHI values per EPA WPS, storage condition requirements (temperature range, humidity, hazmat class), and organic certification reference per USDA NOP. Sourced from SAP S/4HANA MM material master.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`inventory_goods_receipt` (
    `inventory_goods_receipt_id` BIGINT COMMENT 'Unique system-generated surrogate key for each goods receipt record in the inventory domain. Primary key for the goods_receipt data product.',
    `bill_of_lading_id` BIGINT COMMENT 'Foreign key linking to supply.bill_of_lading. Business justification: The BOL is the primary document presented at receiving to initiate the GRN process. Linking goods_receipt to bill_of_lading enables three-way document match (PO + BOL + GRN), supports FSMA traceabilit',
    `bin_location_id` BIGINT COMMENT 'Foreign key linking to inventory.bin_location. Business justification: goods_receipt has storage_bin (STRING) as a denormalized WMS bin reference for the putaway destination. Adding bin_location_id FK links the receipt to the specific bin_location where goods are placed,',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Goods receipts are financial postings within a company code. Multi-entity agriculture operations (multiple farms/subsidiaries) require company code on GR for intercompany inventory transfers, statutor',
    `delivery_schedule_id` BIGINT COMMENT 'Foreign key linking to procurement.delivery_schedule. Business justification: Confirming which scheduled delivery line was fulfilled by a GRN is a core procurement-to-inventory reconciliation process. Agriculture operations track on-time delivery performance and schedule adhere',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Harvest receipt traceability: harvested commodity received into storage must reference the field operation (harvest run) that produced it. This enables yield reconciliation between harvested quantity ',
    `field_crop_plan_id` BIGINT COMMENT 'Reference to the field crop plan associated with a harvest intake receipt. Links harvested commodity back to the originating crop plan for traceability and yield analysis. Null for non-harvest receipt types.',
    `finance_ap_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.finance_ap_invoice. Business justification: Three-way match (PO → GR → Invoice) is a core AP control process. Linking goods_receipt directly to finance_ap_invoice enables automated matching, GR/IR reconciliation, and invoice approval workflows ',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Frost alerts at harvest time cause frost-damaged grain receipts with reduced test weight and elevated damaged kernels. Grain quality managers link goods receipts to the active frost alert for insuranc',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Goods receipts generate GR/IR clearing account postings in the general ledger. Linking GR to GL account supports three-way match reconciliation, GR/IR clearing analysis, and period-close inventory acc',
    `inbound_plan_id` BIGINT COMMENT 'Foreign key linking to supply.inbound_plan. Business justification: The goods receipt is the execution confirmation of an inbound plan. Linking GRN to inbound_plan enables receiving teams to close out planned inbound arrivals, track plan-vs-actual quantity variances, ',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the commodity, seed, chemical, or fertilizer being received. Aligns with SAP MM material master.',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Precipitation events at harvest time cause elevated grain moisture and hail damage, directly affecting goods receipt grade determination and moisture readings. Grain elevator operators link receipts t',
    `purchase_order_id` BIGINT COMMENT 'Reference to the originating Purchase Order (PO) against which this goods receipt is posted. Links GRN to procurement commitment. Null for harvest intake receipts.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Food safety audit trails and GAP/HACCP compliance require identifying which employee received and inspected each grain or input delivery. The receiving employee is a standard accountability field on G',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Goods receipt is created upon arrival of a shipment at the receiving facility. Linking GRN to shipment enables three-way match (PO + shipment + GRN), FSMA receiving-side traceability, and quantity/wei',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: A goods_receipt posting in SAP S/4HANA creates or updates a stock_position record. Adding stock_position_id FK (nullable, populated post-GR posting) links the receipt to the resulting inventory positi',
    `storage_location_id` BIGINT COMMENT 'Reference to the receiving storage location (grain bin, cold storage, warehouse, or field stockpile) where goods are placed upon receipt. Drives FIFO/FEFO lot assignment.',
    `trial_id` BIGINT COMMENT 'Foreign key linking to research.trial. Business justification: Research trial harvest receipt process: grain or seed harvested from trial plots is received into inventory as a goods_receipt. This FK enables traceability from the physical inventory receipt back to',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Agriculture procurement executes GRNs against outline agreements/contracts. Linking goods_receipt to vendor_contract enables contract volume utilization tracking, contracted price verification at rece',
    `vendor_id` BIGINT COMMENT 'Reference to the vendor or supplier from whom goods were received. Populated for purchase receipt types; null for harvest intake or inter-facility transfers.',
    `coa_reference` STRING COMMENT 'Reference number for the Certificate of Analysis (COA) accompanying the received shipment. Documents analytical test results for pesticide residues, mycotoxins, heavy metals, and other quality parameters per food safety standards.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the goods receipt record was first created in the data platform. Used for audit trail and data lineage tracking in the Silver Layer lakehouse.',
    `crop_season` STRING COMMENT 'Agricultural crop season or marketing year associated with the harvested commodity (e.g., 2024-2025). Used for seasonal inventory segregation, WASDE reporting alignment, and crop year cost accounting.',
    `crop_variety` STRING COMMENT 'Specific crop variety or cultivar of the harvested commodity received (e.g., Pioneer P1197AM, Asgrow AG36X6). Supports variety-level traceability, seed performance tracking, and GMO segregation requirements.',
    `elevator_ticket_number` STRING COMMENT 'Grain elevator scale ticket number issued at the point of harvest intake. Captures the official weight and grade determination at the elevator. Applicable to harvest receipt types only.',
    `expiration_date` DATE COMMENT 'Expiration or best-before date for the received material. Mandatory for seed, chemical, and fertilizer inputs. Drives FEFO lot rotation and shelf-life compliance. Null for bulk grain commodities without defined shelf life.',
    `fifo_fefo_flag` STRING COMMENT 'Indicates the stock rotation method applied to this receipt for lot assignment and inventory consumption sequencing. FIFO is standard for grain commodities; FEFO is applied for seed, chemical, and fertilizer inputs with expiration dates.. Valid values are `FIFO|FEFO`',
    `grade_determination` STRING COMMENT 'Official USDA grade assigned to the received commodity based on test weight, moisture, damage, and other grade factors per USDA GIPSA Official Grain Standards. Drives pricing, storage assignment, and end-use routing.. Valid values are `US1|US2|US3|US4|US5|sample_grade`',
    `gross_weight_kg` DECIMAL(18,2) COMMENT 'Total gross weight of the received shipment in kilograms, including packaging and container weight. Used in conjunction with tare weight to calculate net commodity weight.',
    `gtin` STRING COMMENT 'GS1 Global Trade Item Number (GTIN) identifying the received material at the trade item level. Supports GS1 standards-based supply chain traceability and FSMA Section 204 compliance.. Valid values are `^[0-9]{14}$`',
    `harvest_date` DATE COMMENT 'Date on which the crop was harvested in the field prior to intake. Populated for harvest receipt types only. Supports FSMA Section 204 traceability linking field harvest events to inventory lot creation.',
    `is_gmo` BOOLEAN COMMENT 'Indicates whether the received commodity is a Genetically Modified Organism (GMO) or contains GMO material. Critical for identity preservation, segregation, labeling compliance, and export market eligibility.',
    `is_organic_certified` BOOLEAN COMMENT 'Indicates whether the received material is certified organic under the USDA National Organic Program (NOP) or equivalent certification. Drives segregated storage, premium pricing, and organic chain-of-custody documentation.',
    `migo_document_number` STRING COMMENT 'SAP goods movement document number generated by the MIGO transaction upon posting the goods receipt. Used for financial posting reconciliation and audit trail back to SAP S/4HANA MM.. Valid values are `^[0-9]{10}$`',
    `moisture_pct` DECIMAL(18,2) COMMENT 'Moisture content of the received commodity expressed as a percentage, measured at intake. Critical for grain quality grading, shrinkage calculation, storage condition assignment, and USDA grade determination.',
    `net_weight_kg` DECIMAL(18,2) COMMENT 'Net commodity weight in kilograms, calculated as gross weight minus tare weight. Represents the actual quantity of commodity received for inventory posting.',
    `po_line_number` STRING COMMENT 'Line item number within the originating Purchase Order (PO) against which this receipt is posted. Enables partial receipt tracking and PO line-level quantity reconciliation.',
    `quality_inspection_status` STRING COMMENT 'Current status of the quality inspection process for the received goods. Drives hold/release decisions for inventory posting. Integrates with SAP QM inspection lot workflow.. Valid values are `not_inspected|in_progress|passed|failed|conditionally_passed`',
    `quantity_bu` DECIMAL(18,2) COMMENT 'Received quantity expressed in Bushels (BU), the standard unit of measure for grain commodities in North American agricultural markets. Used for commodity trading, WASDE reporting, and inventory valuation.',
    `quantity_cwt` DECIMAL(18,2) COMMENT 'Received quantity expressed in Hundredweight (CWT), used for livestock feed, fertilizer, and certain commodity inventory positions. Supports multi-unit inventory management.',
    `quantity_mt` DECIMAL(18,2) COMMENT 'Received quantity expressed in Metric Tons (MT), used for international trade, export documentation, and global supply chain reporting.',
    `receipt_date` DATE COMMENT 'Calendar date on which the goods were physically received at the facility. Used for FIFO/FEFO lot rotation, aging calculations, and regulatory traceability reporting.',
    `receipt_status` STRING COMMENT 'Current lifecycle status of the goods receipt record. Drives downstream inventory posting, quality inspection workflow, and lot assignment. Rejected receipts trigger return-to-vendor or disposition processes.. Valid values are `draft|pending_inspection|accepted|rejected|partially_accepted|cancelled`',
    `receipt_timestamp` TIMESTAMP COMMENT 'Precise date and time when the goods receipt was recorded in the system. Serves as the principal business event timestamp for audit, traceability, and WMS integration.',
    `receipt_type` STRING COMMENT 'Classification of the receipt event: purchase (supplier delivery against PO), harvest (field intake from crop operations), return (customer return), or transfer (inter-facility stock movement). Determines processing workflow and traceability requirements.. Valid values are `purchase|harvest|return|transfer`',
    `sscc` STRING COMMENT 'GS1 Serial Shipping Container Code (SSCC) for shipment-level tracking of the received pallet or container. Enables end-to-end supply chain traceability from supplier to storage bin.. Valid values are `^[0-9]{18}$`',
    `tare_weight_kg` DECIMAL(18,2) COMMENT 'Weight of the empty container, truck, or packaging in kilograms. Subtracted from gross weight to determine net commodity weight at intake.',
    `test_weight_lb_bu` DECIMAL(18,2) COMMENT 'Test weight of the received grain commodity expressed in pounds per bushel (lb/bu). A key USDA grade factor indicating grain density and quality. Used for grade determination and pricing adjustments.',
    `uom_primary` STRING COMMENT 'Primary unit of measure in which the received quantity is officially recorded for inventory posting. Determines which quantity field (BU, CWT, MT, KG) is the authoritative inventory position.. Valid values are `BU|CWT|MT|KG|LB|EA`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the goods receipt record. Supports change data capture (CDC) and audit trail requirements.',
    CONSTRAINT pk_inventory_goods_receipt PRIMARY KEY(`inventory_goods_receipt_id`)
) COMMENT 'Transactional record of all goods received into inventory including supplier deliveries (GRN processing), harvest intake from field operations (capturing crop season, variety, harvest date, field/parcel of origin, elevator ticket number, gross/tare/net weight), customer returns, and inter-facility transfers. Captures GRN number, PO reference, receipt type (purchase, harvest, return, transfer), vendor/supplier, material with GS1 GTIN/SSCC for shipment-level tracking, quantity received in CWT/BU/MT, receiving location, assigned storage bin, lot assignment, quality inspection status, COA reference, moisture reading at intake, test weight, grade determination, and SAP goods movement document (MIGO). Supports FSMA Section 204 traceability, EU General Food Law Regulation 178/2002, FIFO/FEFO lot assignment at receipt, and links field harvest events to inventory stock positions and commodity lot creation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`goods_issue` (
    `goods_issue_id` BIGINT COMMENT 'Unique surrogate primary key for each goods issue transaction record in the inventory domain.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Customer shipment traceability: goods issues for commodity sales must be linked to the customer account for FSMA lot-level traceability, customer-level volume reporting, and accounts receivable matchi',
    `asset_id` BIGINT COMMENT 'Reference to the equipment or vehicle (sprayer, spreader, planter, feed wagon) used to execute the goods issue or field application.',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the inventory lot (LOT/GRN batch) being consumed, supporting FIFO/FEFO rotation and traceability.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Goods issues are financial transactions posted within a company code. Required for multi-entity agriculture operations to attribute input costs to the correct legal entity for statutory reporting and ',
    `cost_center_id` BIGINT COMMENT 'Reference to the cost center absorbing the COGS (Cost of Goods Sold) for this goods issue, used for financial allocation and reporting.',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Seed, fertilizer, and pesticide goods issues in agriculture are issued to field crews for application operations. Tracking which crew received issued materials is essential for labor cost allocation, ',
    `delivery_location_id` BIGINT COMMENT 'Foreign key linking to customer.delivery_location. Business justification: Outbound shipment execution: goods issues for customer orders must reference the customers delivery location to generate BOL instructions, verify receiving hours and dock availability, and satisfy FS',
    `delivery_order_id` BIGINT COMMENT 'Foreign key linking to sales.delivery_order. Business justification: Outbound logistics execution: a goods issue is the physical inventory deduction triggered by a delivery order in grain trading. This FK links WMS execution to the commercial delivery obligation, suppo',
    `employee_id` BIGINT COMMENT 'Reference to the workforce member (operator, agronomist, or equipment operator) who executed the goods issue or field application.',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Input consumption traceability: seed, fertilizer, and pesticide goods issues must reference the field operation that consumed them for regulatory compliance (PHI/REI tracking), GlobalG.A.P. audit trai',
    `facility_id` BIGINT COMMENT 'Reference to the SAP plant (farm site, processing facility, or distribution center) from which the goods issue originates.',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: Field-level input cost accounting and agronomic compliance: goods issues of seeds, fertilizers, and pesticides must be attributed to the destination field for per-field cost-of-production reports, pes',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Goods issues for seeds, fertilizers, and chemicals post to COGS or input cost GL accounts. Linking goods_issue to gl_account supports input cost reporting by GL account, crop cost allocation, and P&L ',
    `order_line_id` BIGINT COMMENT 'Foreign key linking to sales.order_line. Business justification: Line-level fulfillment tracking: a goods issue fulfills a specific sales order line (e.g., 500 MT corn against line 2). This FK enables line-level delivery confirmation, partial fulfillment tracking, ',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the item being issued (seed, fertilizer, chemical, feed, harvested commodity, etc.).',
    `order_id` BIGINT COMMENT 'Foreign key linking to sales.order. Business justification: Inventory-to-sales fulfillment: goods issues against sales orders are the core outbound commodity movement in agriculture. Replacing the denormalized sales_order_number text with a proper FK enables o',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Outbound goods issues are triggered by shipment execution — inventory is depleted when a shipment departs. Linking goods_issue to shipment enables outbound inventory depletion to be traced to the spec',
    `spray_window_id` BIGINT COMMENT 'Foreign key linking to weather.spray_window. Business justification: Pesticide and agrochemical goods issues must align with open spray windows for EPA label compliance, PHI/REI compliance, and drift prevention. The goods_issue already has phi_compliant and rei_complia',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: A goods_issue reduces a specific stock_position. Adding stock_position_id FK links the issue to the stock position being depleted, enabling real-time inventory depletion tracking and FIFO/FEFO complia',
    `stock_reservation_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_reservation. Business justification: A goods_issue fulfills a stock_reservation in agricultural operations (e.g., issuing fertilizer against a field application reservation, or issuing grain against a sales order reservation). Adding sto',
    `storage_location_id` BIGINT COMMENT 'Reference to the issuing storage location (grain bin, cold storage, warehouse, field stockpile) from which inventory is withdrawn.',
    `trial_id` BIGINT COMMENT 'Foreign key linking to research.trial. Business justification: Research trial input issuance: when inputs (seeds, chemicals, fertilizers) are issued from inventory for a research trial, the goods_issue must reference the trial for cost center allocation, research',
    `vra_prescription_id` BIGINT COMMENT 'Reference to the Variable Rate Application (VRA) prescription that authorized and defined the application rate for this field input goods issue.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to equipment.work_order. Business justification: Maintenance parts consumption tracking: when parts are issued from inventory for equipment repair, the goods issue must reference the work order to enable maintenance cost accounting, parts traceabili',
    `application_rate` DECIMAL(18,2) COMMENT 'Rate at which the agricultural input (fertilizer NPK, crop protection chemical, seed) was applied per unit area (e.g., kg/ha, L/ha, BU/acre). Used for IPM tracking, VRA prescription compliance verification, and MRL calculation.',
    `application_rate_uom` STRING COMMENT 'Unit of measure for the application rate (e.g., KG_PER_HA for fertilizer, L_PER_HA for liquid chemicals, BU_PER_ACRE for seed). Required for VRA prescription compliance and MRL verification.. Valid values are `KG_PER_HA|L_PER_HA|BU_PER_ACRE|LB_PER_ACRE|GAL_PER_ACRE|MT_PER_HA`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this goods issue record was first created in the system (audit trail). Distinct from issue_timestamp which captures the physical event time.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the cost valuation (e.g., USD, EUR, BRL). Supports multi-currency operations for international agricultural trading entities.. Valid values are `^[A-Z]{3}$`',
    `destination_reference` STRING COMMENT 'Business identifier of the destination entity receiving the goods: field ID, pen number, customer delivery address code, production order number, or cost center code. Provides operational traceability to the point of consumption or application.',
    `destination_type` STRING COMMENT 'Classification of the destination receiving the issued goods: agricultural field (for input application), livestock pen (for feed issuance), customer (for sales delivery), production order, cost center (internal consumption), project, or scrap. [ENUM-REF-CANDIDATE: field|pen|customer|production_order|cost_center|project|scrap — 7 candidates stripped; promote to reference product]',
    `document_number` STRING COMMENT 'The externally-known SAP material document number generated upon posting the goods issue (movement type 201, 261, 601, etc.). Serves as the primary business identifier for audit and traceability.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `grn_number` STRING COMMENT 'Goods Receipt Note (GRN) number from the originating inbound receipt, linking the goods issue back to the original procurement receipt for full supply chain traceability and COGS matching.. Valid values are `^GRN-[0-9]{8,12}$`',
    `gtin` STRING COMMENT 'GS1 Global Trade Item Number (GTIN-14) identifying the material at the trade item level. Supports supply chain traceability, MRL compliance verification, and FSMA Traceability Rule requirements.. Valid values are `^[0-9]{14}$`',
    `is_gmo` BOOLEAN COMMENT 'Indicates whether the issued material is a Genetically Modified Organism (GMO). Required for identity preservation programs, COOL (Country of Origin Labeling), EU GMO labeling regulations, and non-GMO certification compliance.',
    `is_organic_certified` BOOLEAN COMMENT 'Indicates whether the issued material is certified organic under the USDA National Organic Program (NOP). Ensures organic integrity is maintained through the supply chain and prevents co-mingling with conventional materials.',
    `issue_status` STRING COMMENT 'Current lifecycle status of the goods issue document: draft (not yet posted), posted (inventory deducted), reversed (corrected via reversal document), cancelled, or pending_approval (awaiting authorization for restricted materials).. Valid values are `draft|posted|reversed|cancelled|pending_approval`',
    `issue_timestamp` TIMESTAMP COMMENT 'The actual date and time the goods issue was posted and inventory was physically withdrawn or applied. This is the principal business event timestamp used for FIFO/FEFO depletion sequencing and COGS recognition.',
    `material_description` STRING COMMENT 'Human-readable description of the material being issued (e.g., Glyphosate 41% Herbicide, Urea 46-0-0 Fertilizer, Pioneer P1197AM Corn Seed, Corn #2 Yellow Dent).',
    `movement_category` STRING COMMENT 'Business-level classification of the goods issue purpose: shipment to customer, internal consumption, field application of agricultural inputs (seeds/NPK fertilizers/crop protection chemicals), livestock feed issuance, production order issue, quality sample, or inventory write-off. [ENUM-REF-CANDIDATE: shipment|consumption|field_application|feed_issuance|production|sample|write_off — 7 candidates stripped; promote to reference product]',
    `movement_type_code` STRING COMMENT 'SAP MM movement type code governing the inventory transaction (e.g., 201=cost center consumption, 261=production order issue, 601=customer delivery, 281=project issue). Drives accounting entries and stock depletion logic.. Valid values are `^[0-9]{3}$`',
    `phi_compliant` BOOLEAN COMMENT 'Indicates whether the goods issue of a crop protection chemical complies with the Pre-Harvest Interval (PHI) — the minimum number of days required between last application and harvest. True = compliant; False = PHI violation requiring corrective action.',
    `posting_date` DATE COMMENT 'The accounting period date on which the goods issue is recognized in the general ledger for COGS allocation. May differ from issue_timestamp when backdating is required for period-end close.',
    `production_order_number` STRING COMMENT 'SAP Production Order number linked to this goods issue when materials are issued to a manufacturing or processing order (movement type 261). Supports production cost tracking and yield analysis.. Valid values are `^PO-[0-9]{8,12}$`',
    `quantity_issued` DECIMAL(18,2) COMMENT 'The quantity of material withdrawn from inventory in the primary unit of measure (UOM). This is the principal quantitative fact of the goods issue transaction.',
    `quantity_issued_mt` DECIMAL(18,2) COMMENT 'Issued quantity normalized to Metric Tons (MT) for cross-commodity analytics, WASDE reporting alignment, and international trade compliance. Derived from quantity_issued and uom at ingestion.',
    `rei_compliant` BOOLEAN COMMENT 'Indicates whether the goods issue and field application of a pesticide complies with the Restricted Entry Interval (REI) per EPA Worker Protection Standard (WPS). True = compliant; False = REI violation requiring immediate safety response.',
    `reversal_document_number` STRING COMMENT 'SAP material document number of the reversal posting (movement type 202, 262, etc.) if this goods issue was reversed. Null if no reversal has been posted. Supports audit trail and inventory reconciliation.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `total_cost_usd` DECIMAL(18,2) COMMENT 'Total COGS value of the goods issue (quantity_issued × unit_cost_usd). Used for cost center allocation, production order costing, and financial period-end close. Stored as a raw transactional value, not a derived KPI.',
    `unit_cost_usd` DECIMAL(18,2) COMMENT 'Standard or moving average cost per unit of measure at the time of goods issue, used for COGS valuation. Sourced from SAP material valuation (standard price or MAP).',
    `uom` STRING COMMENT 'Primary unit of measure for the issued quantity. Agricultural commodities use CWT (Hundredweight), BU (Bushel), or MT (Metric Ton); chemicals/fertilizers use KG, LB, L, or GAL; seeds use BAG or EA. [ENUM-REF-CANDIDATE: CWT|BU|MT|KG|LB|L|GAL|EA|BAG|TON — 10 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this goods issue record in the Silver Layer (e.g., status update, reversal flag, compliance flag recalculation). Supports data lineage and audit requirements.',
    `wms_task_number` STRING COMMENT 'Manhattan Associates WMS task or transfer order number associated with this goods issue, enabling end-to-end warehouse operation traceability from pick task to inventory deduction.. Valid values are `^[A-Z0-9-]{1,30}$`',
    CONSTRAINT pk_goods_issue PRIMARY KEY(`goods_issue_id`)
) COMMENT 'Transactional record of all inventory withdrawals and outbound goods movements including shipments to customers, internal consumption, field application of agricultural inputs (seeds, fertilizers NPK, crop protection chemicals, feed), livestock feed issuance, and production orders. Captures goods issue document number, movement type (shipment, consumption, field_application, feed_issuance, production), material with GS1 GTIN/SSCC, lot, quantity in CWT/BU/MT, issuing location, destination or field/pen of application, operator, equipment used, VRA prescription reference, application rate, REI/PHI compliance flag per EPA WPS, cost center, sales order or production order reference, and SAP movement document. Serves as the SSOT for all inventory consumption including field input application. Supports FIFO/FEFO depletion, IPM tracking, MRL compliance per EU Regulation 396/2005 and Codex Alimentarius, and COGS allocation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`stock_transfer` (
    `stock_transfer_id` BIGINT COMMENT 'Unique surrogate identifier for each stock transfer record in the inventory domain. Primary key for the stock_transfer data product.',
    `alert_id` BIGINT COMMENT 'Foreign key linking to weather.weather_alert. Business justification: Severe weather alerts halt or reroute grain and input stock transfers (road closures, facility shutdowns). Logistics managers link delayed transfers to the causative weather alert for carrier liabilit',
    `asset_id` BIGINT COMMENT 'Identifier of the truck, railcar, or other transport vehicle executing the transfer. Supports fleet tracking, load verification, and chain-of-custody documentation for commodity movements.',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: stock_transfer tracks lot-level movements via denormalized lot_number and grn_number strings. Adding lot_id FK links the transfer to the authoritative commodity_lot record, enabling traceability of lo',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Stock transfers, especially inter-company, must be attributed to the sending company code for financial posting and intercompany reconciliation. Multi-entity agriculture operations require this for st',
    `delivery_order_id` BIGINT COMMENT 'Foreign key linking to sales.delivery_order. Business justification: Positioning inventory for delivery: stock transfers to export terminals or processing facilities are routinely triggered by delivery orders in grain merchandising. This FK enables delivery order fulfi',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Inter-company and inter-plant stock transfers generate GL postings for inventory in-transit accounts and intercompany clearing. Linking to gl_account supports transfer pricing compliance, intercompany',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Grain and input stock transfers between bins or facilities require an accountable employee for authorization and audit. Inventory control reports and internal audit processes in agriculture operations',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: Inter-facility grain transfers require quality inspection at destination (grade verification, moisture check). stock_transfer has quality_inspection_required flag and sap_inspection_lot_number (denorm',
    `intercompany_transaction_id` BIGINT COMMENT 'Foreign key linking to finance.intercompany_transaction. Business justification: When is_inter_company=true, stock transfers generate intercompany financial transactions requiring elimination in consolidated statements. Linking to intercompany_transaction supports intercompany rec',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to inventory.material_master. Business justification: stock_transfer references a material being transferred via denormalized material_number, material_description, and material_type strings. Adding material_master_id FK normalizes this to the SSOT mater',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Inter-facility stock transfers of grain or produce are executed via shipments. Linking stock_transfer to shipment enables end-to-end visibility of inter-elevator movements, replaces denormalized carri',
    `bin_location_id` BIGINT COMMENT 'Foreign key linking to inventory.bin_location. Business justification: stock_transfer has source_storage_bin (STRING) as a denormalized WMS bin reference for the originating bin. Adding source_bin_location_id FK links to the bin_location master for granular WMS bin-level',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: A stock_transfer reduces the source stock_position. Adding source_stock_position_id FK (nullable, populated at transfer initiation) links the transfer to the originating inventory position, enabling s',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: stock_transfer has source_storage_location (STRING) and source_plant (STRING) as denormalized references to the originating storage location. Adding source_storage_location_id FK normalizes this to th',
    `trade_compliance_record_id` BIGINT COMMENT 'Foreign key linking to compliance.trade_compliance_record. Business justification: Inter-company and cross-border commodity stock transfers require phytosanitary certificates, APHIS permits, and trade compliance documentation. The stock_transfer has is_inter_company flag and bol_num',
    `bol_number` STRING COMMENT 'Bill of Lading number issued for inter-facility or plant-to-plant transfers requiring carrier transport. Serves as the legal shipping document and chain-of-custody record for commodity movements.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the stock transfer record was first created in the system, representing the audit trail creation event. Supports data lineage, compliance auditing, and Silver layer ingestion tracking.',
    `destination_plant` STRING COMMENT 'SAP plant code representing the receiving facility, farm site, or processing location to which the stock is being transferred. Required for plant-to-plant stock transport order processing in SAP MM.',
    `destination_storage_bin` STRING COMMENT 'WMS-level bin identifier within the destination storage location where the material will be physically placed. Supports directed putaway logic in Manhattan Associates WMS.',
    `destination_storage_location` STRING COMMENT 'SAP storage location code identifying the target warehouse, grain bin, cold storage unit, or field stockpile area to which inventory is being moved.',
    `estimated_transit_days` STRING COMMENT 'Expected number of days for the material to travel from source to destination facility. Used for in-transit inventory planning, supply chain continuity, and carrier performance benchmarking.',
    `goods_issue_timestamp` TIMESTAMP COMMENT 'Precise timestamp when the goods issue was posted in SAP S/4HANA MM, recording the moment inventory was decremented from the source location. Critical for real-time inventory accuracy and audit trails.',
    `goods_receipt_timestamp` TIMESTAMP COMMENT 'Precise timestamp when the goods receipt was posted at the destination location in SAP S/4HANA MM or confirmed in Manhattan Associates WMS. Marks the completion of the transfer and inventory increment at destination.',
    `gtin` STRING COMMENT 'GS1 Global Trade Item Number (14-digit) identifying the product being transferred. Supports GS1 supply chain standards, COOL compliance, and interoperability with trading partners and regulatory systems.. Valid values are `^d{14}$`',
    `is_inter_company` BOOLEAN COMMENT 'Indicates whether this stock transfer crosses legal entity or company code boundaries, triggering inter-company billing and financial settlement processes in SAP FI/CO. True for transfers between separate legal entities; False for intra-company movements.',
    `notes` STRING COMMENT 'Free-text operational notes or instructions associated with the stock transfer, such as special handling requirements, temperature conditions, or regulatory remarks. Captured by warehouse or logistics personnel.',
    `qty_transferred` DECIMAL(18,2) COMMENT 'The quantity of material being transferred, expressed in the primary unit of measure (UOM). This is the principal quantitative fact of the transfer transaction.',
    `qty_transferred_mt` DECIMAL(18,2) COMMENT 'Transferred quantity normalized to Metric Tons (MT) for cross-commodity comparison, international reporting, and WASDE-aligned analytics. Derived from qty_transferred and uom at ingestion time.',
    `quality_inspection_required` BOOLEAN COMMENT 'Flag indicating whether a quality inspection (QM inspection lot) must be completed upon goods receipt at the destination before the transferred stock is released to unrestricted use. Supports HACCP and food safety compliance.',
    `rotation_method` STRING COMMENT 'Stock rotation method applied to select the lot for this transfer. FIFO (First In First Out) is standard for grain commodities; FEFO (First Expired First Out) is applied for perishables and seed with expiration dates. Ensures compliance with food safety and quality standards.. Valid values are `FIFO|FEFO|LIFO|MANUAL`',
    `sap_movement_type` STRING COMMENT 'SAP S/4HANA MM movement type code governing the inventory posting logic for this transfer (e.g., 311 for storage location transfer, 641 for STO goods issue, 101 for goods receipt). Determines accounting entries and stock update behavior.',
    `sap_sto_number` STRING COMMENT 'SAP S/4HANA MM stock transport order document number associated with this inter-plant or inter-facility transfer. Enables reconciliation with SAP financial and materials management postings.',
    `sscc` STRING COMMENT 'GS1 Serial Shipping Container Code (18-digit) assigned to the pallet or container unit being transferred. Enables unit-level traceability through the supply chain and WMS scanning operations.. Valid values are `^d{18}$`',
    `transfer_date` DATE COMMENT 'The principal business event date on which the stock transfer was initiated or the goods issue was posted in SAP MM. Used for FIFO/FEFO rotation validation, aging analysis, and supply chain reporting.',
    `transfer_order_number` STRING COMMENT 'Externally-known business identifier for the stock transfer, sourced from SAP MM stock transport order (STO) number or Manhattan Associates WMS transfer order number. Used for cross-system traceability and operational communication.',
    `transfer_priority` STRING COMMENT 'Operational priority level assigned to the transfer, used by WMS and logistics teams to sequence execution. Critical transfers may relate to expiring lots, quality holds, or supply chain emergencies.. Valid values are `routine|urgent|critical`',
    `transfer_reason` STRING COMMENT 'Business justification for initiating the stock transfer, such as stock rebalancing, FIFO/FEFO rotation enforcement, quality hold relocation, consolidation, replenishment, or pre-shipment staging. Supports audit and operational reporting.',
    `transfer_status` STRING COMMENT 'Current lifecycle state of the stock transfer workflow. Tracks progression from initiation through execution to completion or cancellation. [ENUM-REF-CANDIDATE: draft|pending|in_transit|completed|cancelled|on_hold — promote to reference product if additional statuses are required]. Valid values are `draft|pending|in_transit|completed|cancelled|on_hold`',
    `transfer_type` STRING COMMENT 'Classification of the stock movement scope: bin-to-bin (within same warehouse), storage location transfer (within same plant), warehouse transfer (between warehouses at same site), plant-to-plant (inter-facility), or cross-dock. Drives routing logic and documentation requirements. [ENUM-REF-CANDIDATE: bin_to_bin|plant_to_plant|warehouse_transfer|storage_location_transfer|cross_dock|field_to_bin — promote to reference product]. Valid values are `bin_to_bin|plant_to_plant|warehouse_transfer|storage_location_transfer|cross_dock`',
    `uom` STRING COMMENT 'Primary unit of measure for the transferred quantity. Agricultural commodities are commonly measured in Bushels (BU), Hundredweight (CWT), or Metric Tons (MT). Chemicals and fertilizers may use gallons (GAL) or liters (L). [ENUM-REF-CANDIDATE: CWT|BU|MT|LB|KG|TON|GAL|L — 8 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the stock transfer record. Supports change detection, incremental data loading in the Databricks Silver layer, and audit trail requirements.',
    `wms_transfer_order_reference` STRING COMMENT 'Reference number assigned by Manhattan Associates WMS for the warehouse-level transfer order. Links the inventory movement to the WMS execution layer for bin-to-bin and warehouse transfer operations.',
    CONSTRAINT pk_stock_transfer PRIMARY KEY(`stock_transfer_id`)
) COMMENT 'Transactional record of inventory movements between storage locations, bins, warehouses, or facilities. Captures transfer order number, source location, destination location, material with GS1 GTIN/SSCC, lot, quantity in CWT/BU/MT, transfer type (bin-to-bin, plant-to-plant, warehouse transfer), WMS transfer order reference, BOL number for inter-facility transfers, carrier, estimated transit time, and transfer reason. Integrates with Manhattan Associates WMS transfer order management and SAP MM stock transport orders.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`cycle_count` (
    `cycle_count_id` BIGINT COMMENT 'Unique surrogate identifier for each cycle count event record in the WMS-driven physical inventory count system.',
    `bin_location_id` BIGINT COMMENT 'Foreign key linking to inventory.bin_location. Business justification: cycle_count has storage_bin (STRING) as a denormalized WMS bin reference. Cycle counts are performed at the bin level in Manhattan Associates WMS. Adding bin_location_id FK links the count to the auth',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the inventory lot (LOT/GRN batch) being counted. Supports FIFO/FEFO rotation tracking and traceability of harvested commodity or input material batches.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Cycle count variances generate financial postings within a company code. Required for period-close physical inventory reconciliation, SOX controls over inventory accuracy, and financial statement asse',
    `facility_id` BIGINT COMMENT 'Reference to the SAP plant (facility/site) where the storage location resides. Supports multi-site inventory accuracy reporting and KPI aggregation.',
    `employee_id` BIGINT COMMENT 'Reference to the workforce employee or contractor assigned to perform the physical count. Links to SAP SuccessFactors workforce record for accountability and audit.',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the inventory item being counted (seed, chemical, fertilizer, or harvested commodity). Links to SAP MM material master.',
    `storage_location_id` BIGINT COMMENT 'Reference to the storage location (grain bin, cold storage, warehouse, field stockpile) where the cycle count was performed. Aligns with SAP MM storage location master and WMS location hierarchy.',
    `warehouse_task_id` BIGINT COMMENT 'Manhattan Associates WMS task identifier assigned to the cycle count activity. Used for WMS workflow tracking, labor management integration, and operational audit trail.',
    `adjustment_posted_flag` BOOLEAN COMMENT 'Indicates whether the confirmed inventory variance from this cycle count has been posted as an inventory adjustment in SAP MM (MI07 Post Differences). True = adjustment posted; False = pending posting. Triggers downstream inventory_adjustment record creation.',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the cycle count results were reviewed and approved by the authorized supervisor. Supports SOX audit trail and FSMA compliance documentation.',
    `count_date` DATE COMMENT 'The calendar date on which the physical inventory count was performed. Principal business event date for the cycle count, used for FIFO/FEFO rotation validation and inventory accuracy KPI reporting.',
    `count_document_number` STRING COMMENT 'Externally-known WMS-generated document number uniquely identifying the cycle count event. Corresponds to the Manhattan Associates WMS count document and SAP MM physical inventory document number used for audit trail and reconciliation.',
    `count_end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the physical count activity was completed at the bin/location level. Combined with count_start_timestamp to calculate count duration for labor and efficiency KPIs.',
    `count_method` STRING COMMENT 'The method used to perform the physical count. Indicates whether the counter used manual tally, RF scanner, barcode scanning, RFID technology, or an automated counting system. Supports accuracy benchmarking by method.. Valid values are `manual|rf_scan|barcode|rfid|automated`',
    `count_qty` DECIMAL(18,2) COMMENT 'The actual physical quantity counted by the counter during the cycle count event. This is the raw observed quantity entered into the WMS or SAP MM physical inventory document.',
    `count_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the physical count activity began at the bin/location level. Used for labor productivity analysis and WMS operational reporting.',
    `count_status` STRING COMMENT 'Current lifecycle status of the cycle count event. Tracks workflow progression from open through completion and approval in the WMS and SAP MM inventory management process.. Valid values are `open|in_progress|completed|approved|cancelled`',
    `count_type` STRING COMMENT 'Classification of the cycle count event indicating whether it was a regularly scheduled count, an ad-hoc count, a recount triggered by variance, an annual physical inventory, or a system-triggered count. [ENUM-REF-CANDIDATE: scheduled|ad_hoc|recount|annual|triggered — promote to reference product if additional types are needed]. Valid values are `scheduled|ad_hoc|recount|annual|triggered`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the cycle count record was first created in the system (WMS or SAP MM). Provides the audit trail creation marker for data lineage and compliance reporting.',
    `expiration_date` DATE COMMENT 'Expiration or best-before date of the lot being counted. Critical for FEFO (First Expired First Out) rotation validation, PHI (Pre-Harvest Interval) compliance for chemical inputs, and food safety regulatory requirements.',
    `grn_number` STRING COMMENT 'Goods Receipt Note (GRN) number associated with the lot being counted. Provides traceability back to the original goods receipt event in SAP MM for supply chain continuity.',
    `gtin` STRING COMMENT 'GS1 Global Trade Item Number (GTIN-14) for the material being counted. Enables barcode scanning integration with Manhattan Associates WMS and supports GS1 traceability standards.. Valid values are `^d{14}$`',
    `material_type` STRING COMMENT 'Classification of the material being counted by agricultural input or output category. Supports domain-specific inventory accuracy reporting across seed, chemical, fertilizer, harvested commodity, and feed stock categories.. Valid values are `seed|chemical|fertilizer|commodity|feed|equipment_part`',
    `original_count_document_number` STRING COMMENT 'For recount records (recount_flag = True), the count document number of the original cycle count that triggered this recount. Enables audit trail linking between original count and recount events.',
    `recount_flag` BOOLEAN COMMENT 'Indicates whether this cycle count record is a recount triggered by an unacceptable variance on a prior count. True = recount; False = original count. Links to the original count via original_count_document_number.',
    `sap_physical_inventory_doc` STRING COMMENT 'SAP S/4HANA MM physical inventory document number (MI01) corresponding to this cycle count event. Provides the cross-system reference key for reconciliation between Manhattan Associates WMS and SAP MM.',
    `scheduled_count_date` DATE COMMENT 'The originally planned date for the cycle count as defined in the WMS cycle count schedule. Compared against count_date to measure schedule adherence and operational compliance.',
    `stock_type` STRING COMMENT 'SAP MM stock type category of the inventory being counted. Determines whether the stock is available for use (unrestricted), under quality hold (quality_inspection), blocked, or restricted. Critical for QM integration.. Valid values are `unrestricted|quality_inspection|blocked|restricted`',
    `system_qty` DECIMAL(18,2) COMMENT 'The inventory quantity recorded in the WMS/SAP system at the time the cycle count was initiated, before the physical count result is entered. Represents the book inventory position used as the baseline for variance calculation.',
    `uom` STRING COMMENT 'The unit of measure in which system_qty, count_qty, and variance_qty are expressed. Agricultural inventory uses CWT (Hundredweight), BU (Bushel), and MT (Metric Ton) for commodities; other units for inputs. Aligns with SAP MM base UOM. [ENUM-REF-CANDIDATE: CWT|BU|MT|LB|KG|EA|GAL|TON — 8 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when the cycle count record was last modified in the system. Tracks updates such as recount entries, variance approvals, and root cause code assignments for audit trail completeness.',
    `variance_pct` DECIMAL(18,2) COMMENT 'The variance quantity expressed as a percentage of the system quantity ((variance_qty / system_qty) * 100). Key inventory accuracy KPI metric used to assess count quality and trigger recount thresholds.',
    `variance_qty` DECIMAL(18,2) COMMENT 'The difference between the physical count quantity and the system quantity (count_qty minus system_qty). A positive value indicates a surplus; a negative value indicates a shortage. Used to trigger inventory adjustment records.',
    `variance_root_cause_code` STRING COMMENT 'Standardized root cause code assigned to explain the inventory variance (e.g., SHRINKAGE, MISCOUNT, MISPLACE, DAMAGE, THEFT, SYSTEM_ERROR, UNIT_CONVERSION). Used for root cause analysis and continuous improvement of inventory accuracy. [ENUM-REF-CANDIDATE: SHRINKAGE|MISCOUNT|MISPLACE|DAMAGE|THEFT|SYSTEM_ERROR|UNIT_CONVERSION|EXPIRY — promote to reference product]',
    `variance_root_cause_description` STRING COMMENT 'Free-text narrative description providing additional detail on the root cause of the inventory variance. Supplements the variance_root_cause_code with counter observations and corrective action notes.',
    `variance_value_usd` DECIMAL(18,2) COMMENT 'The financial value of the inventory variance in US dollars, calculated as variance_qty multiplied by the standard or moving average unit price. Used for financial impact assessment, P&L reporting, and COGS adjustment authorization.',
    CONSTRAINT pk_cycle_count PRIMARY KEY(`cycle_count_id`)
) COMMENT 'WMS-driven cycle count event record capturing scheduled and ad-hoc physical inventory counts at the storage location and bin level. Captures count document number, count date, counter assigned, location/bin counted, material with GS1 GTIN, system quantity vs. physical count quantity in CWT/BU/MT, variance quantity, variance percentage, recount flag, count status, and root cause code for variances. Integrates with Manhattan Associates WMS cycle count module and SAP MM inventory management. Supports inventory accuracy KPI tracking and triggers inventory_adjustment records for confirmed variances.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`adjustment` (
    `adjustment_id` BIGINT COMMENT 'Unique surrogate identifier for each inventory adjustment transaction record in the Agriculture lakehouse Silver layer. Primary key for the inventory_adjustment data product.',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the commodity, seed, chemical, or fertilizer being adjusted. Aligns with SAP S/4HANA MM material master.',
    `adjustment_material_material_master_id` BIGINT COMMENT 'FK to inventory.material_master',
    `employee_id` BIGINT COMMENT 'Employee ID of the authorized approver who reviewed and approved the inventory adjustment. Required for SOX internal controls and FSMA audit trail compliance. References SAP SuccessFactors employee master.',
    `bin_location_id` BIGINT COMMENT 'Foreign key linking to inventory.bin_location. Business justification: inventory_adjustment has storage_bin (STRING) as a denormalized WMS bin reference. Adjustments (shrinkage, moisture loss, quality downgrades) occur at specific bin locations. Adding bin_location_id FK',
    `case_id` BIGINT COMMENT 'Foreign key linking to customer.case. Business justification: Customer claim resolution: inventory adjustments for short shipments, quality rejections, or returns are initiated by customer cases. Linking adjustment to case enables claim-to-adjustment reconciliat',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the commodity or material lot (LOT/batch) being adjusted. Supports FIFO/FEFO rotation tracking and traceability per FSMA requirements.',
    `company_code_id` BIGINT COMMENT 'Foreign key linking to finance.company_code. Business justification: Inventory adjustments generate financial postings within a company code. Required for multi-entity agriculture operations to correctly attribute shrinkage losses and write-offs to the appropriate lega',
    `cycle_count_id` BIGINT COMMENT 'Foreign key linking to inventory.cycle_count. Business justification: inventory_adjustment has cycle_count_document (STRING) referencing the triggering cycle count document. In WMS-driven operations, cycle count variances automatically trigger inventory adjustments. Add',
    `environmental_incident_id` BIGINT COMMENT 'Foreign key linking to sustainability.environmental_incident. Business justification: Inventory write-downs caused by spills, contamination, or flood damage must be linked to the triggering environmental incident for EPA regulatory reporting, insurance claims, and GRI 307 compliance. C',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Inventory adjustments for shrinkage, spoilage, and write-offs post to specific GL accounts (inventory write-down, shrinkage expense). Direct FK supports period-close reconciliation of inventory value ',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Inventory adjustments generate accounting documents (sap_accounting_doc_number is a denormalized reference). Direct FK to journal_entry supports audit trail for shrinkage/write-off postings, SOX contr',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Inventory adjustments for quality-related losses (mycotoxin-contaminated grain disposal, MRL-failed lot destruction) are triggered by nonconformance events. Direct FK enables P&L impact reporting by n',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Hail and flooding cause commodity shrinkage adjustments in grain storage — a named business process for insurance and financial reporting. Grain accountants require this link to document weather-cause',
    `quarantine_hold_id` BIGINT COMMENT 'Foreign key linking to inventory.quarantine_hold. Business justification: A quarantine_hold resolution (disposition decision: destroy, rework, return) triggers an inventory_adjustment to reflect the quantity change. Adding quarantine_hold_id FK (nullable) to inventory_adjus',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: An inventory_adjustment modifies a specific stock_position (shrinkage, moisture loss, quality downgrade). Adding stock_position_id FK directly links the adjustment to the affected position, enabling p',
    `storage_location_id` BIGINT COMMENT 'Reference to the storage location (grain bin, cold storage, warehouse, field stockpile) where the inventory adjustment occurred. Aligns with SAP S/4HANA MM storage location master.',
    `waste_event_id` BIGINT COMMENT 'Foreign key linking to sustainability.waste_event. Business justification: Inventory adjustments for spoilage, expired product disposal, and condemned grain generate regulated waste events requiring EPA waste manifests and GRI 306 reporting. Linking inventory_adjustment to w',
    `adjusted_qty` DECIMAL(18,2) COMMENT 'Inventory quantity after the adjustment has been applied. Expressed in the primary unit of measure (CWT, BU, or MT). Represents the corrected on-hand balance.',
    `adjustment_status` STRING COMMENT 'Current workflow lifecycle state of the inventory adjustment record. Controls whether the adjustment has been approved, posted to the general ledger, or reversed.. Valid values are `draft|pending_approval|approved|posted|reversed|cancelled`',
    `adjustment_type` STRING COMMENT 'Classification of the inventory adjustment event. Shrinkage covers moisture loss, drying shrink, handling loss, and storage deterioration. Cycle count variance corrects WMS discrepancies. Damage write-off records pest damage or physical loss. Quality downgrade reclassifies commodity grade. Reclassification moves stock between categories.. Valid values are `shrinkage|cycle_count_variance|damage_write_off|quality_downgrade|reclassification`',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the inventory adjustment was formally approved by the authorized approver. Supports SOX audit trail and segregation of duties compliance.',
    `approver_name` STRING COMMENT 'Full name of the employee who approved the inventory adjustment. Retained as a denormalized audit field to preserve the historical record even if the employee record changes.',
    `cause_code` STRING COMMENT 'Standardized root cause code identifying the reason for the inventory discrepancy or shrinkage event (e.g., MOIST-LOSS, PEST-DMG, PROC-ERR, CYCLE-VAR). Sourced from SAP MM cause code configuration. [ENUM-REF-CANDIDATE: promote to reference product with full cause code taxonomy]',
    `corrective_action` STRING COMMENT 'Description of the corrective action implemented to prevent recurrence of the inventory discrepancy or shrinkage event. Supports continuous improvement and GFSI/SQF audit requirements.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the inventory adjustment record was first created in the system. Audit field for data lineage and Silver layer ingestion tracking.',
    `document_number` STRING COMMENT 'Externally-known business identifier for the inventory adjustment document. Generated by SAP S/4HANA MM or Manhattan Associates WMS at time of posting. Used for audit trail and cross-system reconciliation.. Valid values are `^ADJ-[0-9]{10}$`',
    `grn_number` STRING COMMENT 'Goods Receipt Note (GRN) reference number linking the adjusted inventory to its original inbound receipt document. Enables traceability from adjustment back to procurement receipt.',
    `is_reversal` BOOLEAN COMMENT 'Flag indicating whether this adjustment record is a reversal of a previously posted adjustment. True when the record cancels a prior adjustment document. Supports audit trail integrity.',
    `movement_type` STRING COMMENT 'SAP S/4HANA MM movement type code governing the inventory posting (e.g., 551 for scrapping, 701 for physical inventory difference, 344 for transfer posting). Determines the accounting impact and stock category affected.',
    `original_qty` DECIMAL(18,2) COMMENT 'Inventory quantity recorded before the adjustment event was applied. Expressed in the primary unit of measure (CWT, BU, or MT). Baseline for variance calculation.',
    `plant_code` STRING COMMENT 'SAP S/4HANA plant code identifying the facility (farm, processing plant, warehouse) where the inventory adjustment occurred. Supports multi-site inventory management.',
    `posting_date` DATE COMMENT 'Accounting posting date on which the inventory adjustment was recorded in SAP S/4HANA FI/MM. Determines the fiscal period for COGS and inventory valuation impact. May differ from shrinkage_event_date.',
    `reason_code` STRING COMMENT 'Business reason code for the inventory adjustment as defined in SAP S/4HANA MM configuration (e.g., physical inventory difference, goods issue correction, quality rejection). Distinct from cause_code which identifies root cause; reason_code identifies the business justification category.',
    `reason_description` STRING COMMENT 'Free-text narrative description of the specific reason for the inventory adjustment. Provides context beyond the structured reason_code for audit trail and corrective action documentation.',
    `reversed_document_number` STRING COMMENT 'Adjustment document number of the original posting that this record reverses. Populated only when is_reversal is True. Enables bidirectional audit trail linkage between original and reversal documents.',
    `shrinkage_event_date` DATE COMMENT 'Calendar date on which the shrinkage event (moisture loss, pest damage, storage deterioration) physically occurred. May differ from the adjustment posting date. Critical for seasonal shrinkage trend analysis.',
    `shrinkage_pct` DECIMAL(18,2) COMMENT 'Percentage of original inventory quantity lost due to the shrinkage event (variance_qty / original_qty * 100). Used for shrinkage trend analysis and benchmarking by storage type, commodity, and season.',
    `shrinkage_type` STRING COMMENT 'Specific category of shrinkage event when adjustment_type is shrinkage. Distinguishes moisture loss during drying, physical handling loss, storage deterioration over time, pest damage, or quality-driven downgrade. [ENUM-REF-CANDIDATE: moisture_loss|drying_shrink|handling_loss|storage_deterioration|pest_damage|quality_downgrade|other — promote to reference product]',
    `stock_type_after` STRING COMMENT 'SAP stock category of the inventory after the adjustment has been applied. Used for reclassification adjustments to confirm the target stock category.. Valid values are `unrestricted|quality_inspection|blocked|restricted|in_transit`',
    `stock_type_before` STRING COMMENT 'SAP stock category of the inventory before the adjustment was applied. Relevant for reclassification adjustments that move stock between unrestricted, quality inspection, blocked, or restricted categories.. Valid values are `unrestricted|quality_inspection|blocked|restricted|in_transit`',
    `unit_cost_usd` DECIMAL(18,2) COMMENT 'Standard or moving average cost per unit of measure at the time of the adjustment, in US Dollars. Used to calculate the financial value impact of the inventory adjustment for COGS accuracy.',
    `uom_primary` STRING COMMENT 'Primary unit of measure for all quantity fields (original_qty, adjusted_qty, variance_qty). Agricultural commodities are measured in Hundredweight (CWT), Bushels (BU), or Metric Tons (MT) per USDA standards.. Valid values are `CWT|BU|MT|LB|KG|TON`',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when the inventory adjustment record was last modified in the system. Supports incremental data pipeline processing and audit trail in the Databricks Silver layer.',
    `value_impact_usd` DECIMAL(18,2) COMMENT 'Estimated financial impact of the inventory adjustment in US Dollars (variance_qty multiplied by unit_cost_usd). Represents the COGS charge or inventory write-down posted to the general ledger. Negative values indicate inventory value reduction.',
    `variance_qty` DECIMAL(18,2) COMMENT 'Net quantity difference between original and adjusted quantities (original_qty minus adjusted_qty). Negative values indicate stock reduction (shrinkage/loss); positive values indicate stock increase (count correction). Expressed in primary UOM.',
    `wms_task_number` STRING COMMENT 'Manhattan Associates WMS task or cycle count task number associated with this inventory adjustment. Provides cross-system traceability between the WMS cycle count event and the SAP inventory posting.',
    CONSTRAINT pk_adjustment PRIMARY KEY(`adjustment_id`)
) COMMENT 'Transactional record of all inventory quantity and value adjustments including shrinkage events (moisture loss/drying shrink, handling loss, storage deterioration, pest damage, quality downgrade), cycle count variance corrections, damage write-offs, and reclassifications. Captures adjustment document number, adjustment type (shrinkage, variance, damage, downgrade, reclassification), material, lot, location, original quantity, adjusted quantity, variance quantity in CWT/BU/MT, shrinkage type and percentage, cause code, adjustment reason code, corrective action taken, approver, cost impact, estimated value impact, shrinkage event date, and SAP accounting document reference. Serves as the SSOT for all shrinkage tracking, shrinkage trend analysis and benchmarking by storage type, commodity, and season. Supports COGS accuracy for commodity accounting and provides complete audit trail for all inventory corrections.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`bin_location` (
    `bin_location_id` BIGINT COMMENT 'Unique surrogate identifier for each bin location record within the warehouse management system. Serves as the primary key for the bin_location data product in the Databricks Silver Layer.',
    `plant_id` BIGINT COMMENT 'Reference to the SAP plant (facility or production site) to which this bin location belongs. Aligns bin-level inventory tracking with SAP S/4HANA MM plant-level stock management.',
    `storage_location_id` BIGINT COMMENT 'Reference to the parent storage location (grain bin facility, cold storage building, warehouse, or field stockpile site) that contains this bin. Enables hierarchical slot management within Manhattan Associates WMS and SAP S/4HANA MM.',
    `aisle_code` STRING COMMENT 'Alphanumeric code identifying the aisle within the storage section where this bin is physically located. Used for optimizing pick paths and directing warehouse personnel to the correct physical location.. Valid values are `^[A-Z0-9-]{1,10}$`',
    `allowed_material_types` STRING COMMENT 'Comma-separated list of SAP material type codes permitted for storage in this bin (e.g., FERT,DUNG,ERSA for fertilizers, seeds, and spare parts). Enforces material segregation rules and prevents incompatible commodity co-mingling. Managed in SAP S/4HANA MM material type configuration.',
    `bin_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the bin within its storage location. Used in WMS slot management, pick/put-away instructions, and RFID scanning operations. Corresponds to the WMS bin number in Manhattan Associates.. Valid values are `^[A-Z0-9-]{2,30}$`',
    `bin_name` STRING COMMENT 'Human-readable descriptive name or label for the bin location (e.g., North Grain Bin Cell 3A, Cold Bay 12, Rack Position A-02-03). Used in operational reports and warehouse floor maps.',
    `bin_status` STRING COMMENT 'Current operational lifecycle status of the bin location within the WMS. Active bins are available for put-away and picking; blocked bins are temporarily unavailable; reserved bins are pre-allocated; under_maintenance bins are being serviced; decommissioned bins are permanently retired.. Valid values are `active|inactive|blocked|reserved|under_maintenance|decommissioned`',
    `bin_type` STRING COMMENT 'Classification of the physical bin structure. Determines storage rules, capacity constraints, and compatible material types. Grain bin cells hold harvested commodities; rack positions hold packaged goods; cold storage bays hold perishables; floor stacks hold palletized inventory; bulk piles hold loose commodities; chemical cabinets hold agrochemicals. [ENUM-REF-CANDIDATE: grain_bin_cell|rack_position|cold_storage_bay|floor_stack|bulk_pile|chemical_cabinet — promote to reference product]. Valid values are `grain_bin_cell|rack_position|cold_storage_bay|floor_stack|bulk_pile|chemical_cabinet`',
    `capacity_bu` DECIMAL(18,2) COMMENT 'Maximum storage capacity of the bin expressed in Bushels (BU), the standard unit of measure for grain commodities in US agricultural operations. Used for grain bin cell utilization planning and WASDE reporting alignment.',
    `capacity_cwt` DECIMAL(18,2) COMMENT 'Maximum storage capacity of the bin expressed in Hundredweight (CWT), a standard unit used for livestock feed, fertilizer, and certain commodity pricing in US agricultural markets.',
    `capacity_mt` DECIMAL(18,2) COMMENT 'Maximum storage capacity of the bin expressed in Metric Tons (MT). Used for international trade documentation, export compliance, and alignment with global commodity reporting standards (CIF/FOB contracts).',
    `commissioning_date` DATE COMMENT 'Date the bin location was officially commissioned and made available for use in the WMS. Marks the start of the bins operational lifecycle and is used for asset age tracking, depreciation scheduling, and capacity planning.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the bin location record was first created in the system. Provides audit trail for data lineage and supports SOX financial reporting controls for inventory master data governance.',
    `current_utilization_pct` DECIMAL(18,2) COMMENT 'Current fill level of the bin expressed as a percentage of its maximum capacity. Calculated from WMS inventory positions and updated on each stock movement. Drives replenishment triggers and bin assignment logic in Manhattan Associates WMS.',
    `decommissioning_date` DATE COMMENT 'Date the bin location was permanently decommissioned and removed from active WMS operations. Nullable for active bins. Used for capacity planning, asset retirement reporting, and historical inventory analysis.',
    `height_cm` DECIMAL(18,2) COMMENT 'Physical height dimension of the bin location in centimeters. Determines compatibility with stacked pallets, tall containers, or bulk commodity storage. Used in conjunction with level_code for equipment selection (e.g., high-reach forklift requirements).',
    `is_gmo_segregated` BOOLEAN COMMENT 'Indicates whether this bin is designated for GMO-segregated commodity storage. When True, the bin is used exclusively for non-GMO or identity-preserved commodities, supporting COOL (Country of Origin Labeling) and non-GMO supply chain traceability requirements.',
    `is_hazmat_compatible` BOOLEAN COMMENT 'Indicates whether this bin is certified and equipped to store hazardous materials such as pesticides, herbicides, or fertilizers with hazmat classifications. When True, the bin meets EPA and OSHA storage requirements for agrochemicals. Prevents co-mingling of hazmat and food-grade commodities.',
    `is_organic_segregated` BOOLEAN COMMENT 'Indicates whether this bin is designated exclusively for USDA National Organic Program (NOP) certified organic commodities. When True, the bin must be physically segregated from non-organic storage to maintain organic certification integrity and prevent commingling.',
    `last_cleaned_date` DATE COMMENT 'Date the bin location was last cleaned and sanitized. Critical for food safety compliance, particularly for grain bins and cold storage bays. Supports HACCP sanitation monitoring, FSMA Preventive Controls, and GLOBALG.A.P. hygiene audit requirements.',
    `last_cycle_count_date` DATE COMMENT 'Date of the most recent WMS-driven cycle count performed on this bin location. Used to schedule future cycle counts, assess inventory accuracy compliance, and support FSMA traceability requirements. Sourced from Manhattan Associates WMS cycle count completion records.',
    `last_inspected_date` DATE COMMENT 'Date of the most recent physical inspection of the bin location for structural integrity, pest presence, moisture ingress, or contamination. Supports USDA APHIS pest management compliance and GFSI audit readiness.',
    `length_cm` DECIMAL(18,2) COMMENT 'Physical length dimension of the bin location in centimeters. Used for slotting optimization, determining compatible pallet or container sizes, and space utilization analysis within the warehouse management system.',
    `level_code` STRING COMMENT 'Alphanumeric code identifying the vertical level or tier of the bin within a rack or storage structure. Used for height-based storage rules and equipment selection (e.g., forklift reach requirements).. Valid values are `^[A-Z0-9-]{1,10}$`',
    `max_temp_celsius` DECIMAL(18,2) COMMENT 'Maximum allowable storage temperature in degrees Celsius for this bin location. Exceeding this threshold triggers WMS alerts and may require stock relocation to prevent quality degradation or food safety violations.',
    `max_weight_kg` DECIMAL(18,2) COMMENT 'Maximum allowable weight load for this bin location in kilograms. Critical for structural safety compliance, particularly for rack positions and floor stacks. Prevents overloading that could cause structural failure or OSHA safety violations.',
    `min_temp_celsius` DECIMAL(18,2) COMMENT 'Minimum allowable storage temperature in degrees Celsius for this bin location. Used to enforce cold chain compliance and prevent commodity spoilage. Monitored via IoT sensors integrated with the WMS.',
    `put_away_strategy` STRING COMMENT 'WMS put-away strategy assigned to this bin, governing how incoming stock is directed to this location. Fixed bins always receive the same material; open bins accept any compatible material; bulk bins receive large-volume commodity transfers; addition bins consolidate partial pallets; next_empty bins are filled sequentially.. Valid values are `fixed|open|bulk|addition|next_empty`',
    `rfid_tag_number` STRING COMMENT 'RFID tag identifier physically attached to the bin location for automated scanning and real-time inventory tracking. Enables touchless bin identification during put-away, picking, and cycle count operations in Manhattan Associates WMS.. Valid values are `^[A-Z0-9]{8,24}$`',
    `rotation_method` STRING COMMENT 'Inventory rotation method applied to stock stored in this bin. FIFO (First In First Out) and FEFO (First Expired First Out) are standard for food-grade commodities to minimize spoilage and ensure compliance with food safety regulations. LIFO and LEFO may apply to non-perishable inputs.. Valid values are `FIFO|FEFO|LIFO|LEFO`',
    `row_code` STRING COMMENT 'Alphanumeric code identifying the row within the aisle for this bin. Combined with aisle_code and level_code to form the full physical coordinate of the bin within the warehouse.. Valid values are `^[A-Z0-9-]{1,10}$`',
    `sap_storage_bin` STRING COMMENT 'The storage bin identifier as defined in SAP S/4HANA Warehouse Management (WM) module. Used for cross-system reconciliation between Manhattan Associates WMS and SAP S/4HANA MM inventory postings. Corresponds to the LGPLA field in SAP WM.. Valid values are `^[A-Z0-9-]{1,18}$`',
    `storage_section_code` STRING COMMENT 'Code identifying the logical storage section or zone within the storage location to which this bin belongs (e.g., SEC-A, ZONE-COLD-1). Supports zone-based picking strategies and inventory segmentation in Manhattan Associates WMS.. Valid values are `^[A-Z0-9-]{1,20}$`',
    `temperature_zone` STRING COMMENT 'Temperature-controlled zone classification for the bin. Determines which commodities (e.g., fresh produce, frozen goods, ambient grain) can be stored in this bin. Critical for cold chain compliance and food safety under FDA and FSMA requirements.. Valid values are `ambient|refrigerated|frozen|controlled_atmosphere|heated`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the bin location record. Used for change data capture (CDC) in the Databricks Silver Layer pipeline and supports audit trail requirements for inventory master data governance.',
    `width_cm` DECIMAL(18,2) COMMENT 'Physical width dimension of the bin location in centimeters. Used alongside length and height for slotting optimization and determining whether specific pallet configurations or container types can be accommodated.',
    `wms_bin_number` STRING COMMENT 'The bin identifier as recorded in Manhattan Associates WMS, used for system-to-system integration and reconciliation with SAP S/4HANA WM storage bin records. This is the operational system key used in WMS transactions.. Valid values are `^[A-Z0-9-.]{2,40}$`',
    CONSTRAINT pk_bin_location PRIMARY KEY(`bin_location_id`)
) COMMENT 'Granular WMS bin-level location master within a storage location, representing individual grain bin cells, rack positions, cold storage bays, or floor stack positions. Captures bin code, bin type, storage section, maximum capacity in BU/MT/CWT, current utilization, temperature zone, hazmat compatibility flag, RFID tag, and WMS bin status. Enables precise slot management and bin-level inventory tracking within Manhattan Associates WMS.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`stock_reservation` (
    `stock_reservation_id` BIGINT COMMENT 'Unique surrogate identifier for each stock reservation record in the inventory domain. Primary key for the stock_reservation data product.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Customer order fulfillment: stock reservations in agriculture are created against customer sales orders. Linking to customer.account enables customer-level reserved inventory reporting, credit exposur',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the specific inventory lot (LOT/batch) being reserved, enabling FIFO/FEFO rotation and traceability to the originating Goods Receipt Note (GRN).',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Stock reservations are made against cost centers for budget commitment tracking in SAP MM. The existing plain cost_center attribute is a denormalized text reference. Direct FK enables budget vs. act',
    `delivery_location_id` BIGINT COMMENT 'Foreign key linking to customer.delivery_location. Business justification: Commodity fulfillment logistics: reservations for customer shipments must reference the customers receiving facility to plan transportation, verify temperature-controlled delivery capability, and con',
    `facility_id` BIGINT COMMENT 'Reference to the SAP plant (farm site, processing facility, or distribution center) where the reserved stock is physically held.',
    `field_crop_plan_id` BIGINT COMMENT 'Foreign key linking to crop.field_crop_plan. Business justification: A field crop plan drives material requirements (seed, fertilizer, chemicals) that are reserved in inventory. Linking stock_reservation to field_crop_plan supports MRP-driven inventory reservation for ',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the item being reserved (seed, fertilizer, chemical, harvested commodity, etc.).',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Agronomists and planners create stock reservations for seed, fertilizer, and pesticide for specific field operations. Tracking the requesting employee is required for operational accountability, budge',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Contract delivery obligation management: in grain merchandising, inventory is reserved against forward sales contracts (not just spot orders). This FK supports contract position reporting — tracking h',
    `order_id` BIGINT COMMENT 'Foreign key linking to sales.order. Business justification: ATP (Available-to-Promise) and order fulfillment: when a sales order is placed, inventory is reserved against it. This FK replaces the denormalized originating_order_number text field and enables real',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: stock_reservation earmarks specific inventory for planned consumption. It already references material_master, storage_location, and commodity_lot — the same composite key that identifies a stock_posit',
    `storage_location_id` BIGINT COMMENT 'Reference to the storage location (grain bin, cold storage, warehouse, field stockpile) from which the reserved stock will be drawn.',
    `trial_id` BIGINT COMMENT 'Foreign key linking to research.trial. Business justification: Research trial input reservation process: inventory inputs (seeds, agrochemicals, fertilizers) are reserved ahead of trial application windows. This FK links the reservation to the specific trial for ',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to equipment.work_order. Business justification: Maintenance planning: parts are reserved in inventory against a specific work order before maintenance begins. This FK enables MRO inventory planning, parts availability checks for scheduled maintenan',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this stock reservation record was first created in the data lakehouse Silver layer. Distinct from reservation_date (the business event time).',
    `expiry_date` DATE COMMENT 'Date after which this reservation automatically expires if not fulfilled. Prevents indefinite stock lock-up and supports FEFO rotation. Distinct from the materials shelf-life expiration date.',
    `grn_number` STRING COMMENT 'Goods Receipt Note (GRN) number associated with the lot being reserved. Links the reservation to the original inbound goods receipt event for supply chain continuity and audit.',
    `is_backflush` BOOLEAN COMMENT 'Indicates whether the goods issue against this reservation will be processed via backflushing (automatic goods issue at production order confirmation) rather than manual withdrawal. Relevant for SAP PP integration.',
    `is_final_issue` BOOLEAN COMMENT 'Indicates whether this reservation has been marked as final issue in SAP (no further goods issues expected). When True, the reservation is closed to further withdrawals even if open quantity remains.',
    `lot_number` STRING COMMENT 'Human-readable batch/lot identifier (LOT) for the reserved stock, used for FIFO/FEFO rotation, traceability, and regulatory compliance (FSMA, GLOBALG.A.P.).',
    `material_description` STRING COMMENT 'Short descriptive name of the reserved material (e.g., Corn Seed — Pioneer P1197AM, Anhydrous Ammonia 82% N, Wheat — Hard Red Winter). Supports readability in operational reports without requiring a material master join.',
    `material_expiration_date` DATE COMMENT 'Shelf-life expiration date of the reserved lot/batch. Critical for FEFO rotation, PHI (Pre-Harvest Interval) compliance, and food safety (FSMA, HACCP). Distinct from the reservations own expiry date.',
    `material_number` STRING COMMENT 'SAP material number (alphanumeric) for the reserved item, as maintained in the Material Master. Provides a human-readable cross-system identifier alongside the surrogate material_id.',
    `movement_type` STRING COMMENT 'SAP S/4HANA inventory movement type code associated with the planned goods issue against this reservation (e.g., 261 for production order goods issue, 601 for sales order delivery). Drives accounting and inventory postings.',
    `notes` STRING COMMENT 'Free-text operational notes or instructions associated with the reservation (e.g., handling requirements, application instructions, quality remarks). Sourced from SAP reservation text or WMS comments.',
    `originating_order_type` STRING COMMENT 'Discriminator identifying the type of source document that created this reservation, enabling correct navigation to the originating system record (SAP PP, SD, MM, or FMIS).. Valid values are `production_order|sales_order|transfer_order|field_application_plan|purchase_order`',
    `phi_days` STRING COMMENT 'Pre-Harvest Interval (PHI) in days applicable to the reserved chemical or pesticide material. Ensures reserved crop protection inputs are not applied within the restricted window before harvest, per EPA label requirements.',
    `qty_fulfilled` DECIMAL(18,2) COMMENT 'Quantity of the reservation that has already been withdrawn/consumed against this reservation. Enables partial fulfillment tracking and open-quantity calculation.',
    `qty_reserved` DECIMAL(18,2) COMMENT 'Total quantity of the material earmarked by this reservation, expressed in the primary unit of measure (UOM). Prevents double-allocation by reducing available stock in the inventory position.',
    `qty_reserved_bu` DECIMAL(18,2) COMMENT 'Reserved quantity converted to Bushels (BU) for grain commodity reporting and USDA/WASDE alignment. Null for non-grain materials.',
    `qty_reserved_mt` DECIMAL(18,2) COMMENT 'Reserved quantity converted to Metric Tons (MT) for international trade, export documentation, and CIF/FOB contract compliance.',
    `requirement_date` DATE COMMENT 'The date by which the reserved stock must be available for consumption or shipment. Drives MRP planning in SAP S/4HANA and supply chain scheduling.',
    `reservation_date` TIMESTAMP COMMENT 'The principal business event timestamp — the date and time when the stock reservation was created and the stock was earmarked. Distinct from the audit created_timestamp.',
    `reservation_number` STRING COMMENT 'Externally-known, human-readable reservation document number generated by SAP S/4HANA MM (e.g., RES-0000123456). Used for cross-system reference and supply chain communication.. Valid values are `^RES-[0-9]{10}$`',
    `reservation_status` STRING COMMENT 'Current lifecycle state of the stock reservation. open — earmarked but not yet consumed; partially_fulfilled — some quantity withdrawn; fulfilled — fully consumed; cancelled — voided before use; expired — requirement date passed without fulfillment.. Valid values are `open|partially_fulfilled|fulfilled|cancelled|expired`',
    `reservation_type` STRING COMMENT 'Classification of the business purpose driving the reservation. production — for a manufacturing/processing order; sales — earmarked for a Sales Order (SO); transfer — stock transfer between locations; field_application — reserved for crop input application (fertilizer, chemical); quality_hold — held for QM inspection; return — reserved for return processing. [ENUM-REF-CANDIDATE: production|sales|transfer|field_application|quality_hold|return — promote to reference product]. Valid values are `production|sales|transfer|field_application|quality_hold|return`',
    `rotation_method` STRING COMMENT 'Inventory rotation method applied when selecting the lot for this reservation. FIFO (First In First Out) for standard commodities; FEFO (First Expired First Out) for perishables and chemicals with PHI/expiry constraints.. Valid values are `FIFO|FEFO|LIFO|MANUAL`',
    `sap_reservation_doc_number` STRING COMMENT 'The internal SAP document number for the reservation record (10-digit numeric string from MB21). Provides the authoritative source-system reference for reconciliation with SAP S/4HANA MM.',
    `special_stock_indicator` STRING COMMENT 'SAP special stock category for the reserved material. E — sales order stock; Q — project stock; K — consignment stock at customer; W — consignment stock at vendor; blank — standard own stock.. Valid values are `E|Q|K|W|`',
    `stock_type` STRING COMMENT 'SAP stock category from which the reservation draws inventory. unrestricted — freely available stock; quality_inspection — stock under QM hold; blocked — blocked stock; restricted — restricted-use stock (e.g., organic-certified).. Valid values are `unrestricted|quality_inspection|blocked|restricted`',
    `uom_primary` STRING COMMENT 'Primary unit of measure for the reserved quantity. Agricultural commodities use CWT (Hundredweight), BU (Bushel), or MT (Metric Ton); chemicals/fertilizers may use KG, LB, L, or GAL. [ENUM-REF-CANDIDATE: CWT|BU|MT|KG|LB|L|GAL|TON|EA — 9 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording the most recent modification to this stock reservation record in the data lakehouse. Supports change data capture (CDC) and data lineage tracking.',
    `wbs_element` STRING COMMENT 'SAP Project System WBS element associated with this reservation, used when stock is reserved for a capital project (e.g., irrigation infrastructure, new grain bin construction). Supports CAPEX tracking.',
    `wms_reservation_reference` STRING COMMENT 'Corresponding reservation or allocation reference number in Manhattan Associates WMS. Enables reconciliation between SAP MM reservations and WMS-level stock allocations.',
    CONSTRAINT pk_stock_reservation PRIMARY KEY(`stock_reservation_id`)
) COMMENT 'Transactional record of inventory reservations that earmark stock for planned consumption — including production orders, sales orders, and field application plans. Captures reservation number, material, lot, reserved quantity in CWT/BU/MT, reservation type (production, sales, transfer), requirement date, originating order reference, fulfillment status, and expiry date. Prevents double-allocation and supports supply chain continuity planning.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`reorder_policy` (
    `reorder_policy_id` BIGINT COMMENT 'Unique surrogate identifier for the reorder policy configuration record. Primary key for this master configuration entity in the inventory domain.',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to sales.demand_forecast. Business justification: S&OP (Sales & Operations Planning): demand forecasts directly drive reorder policies in agricultural supply chains — forecast volumes determine safety stock levels and reorder points. This FK document',
    `input_catalog_id` BIGINT COMMENT 'Foreign key linking to procurement.input_catalog. Business justification: Agriculture reorder policies must source only from approved input catalog items (FSMA preventive controls, EPA registration compliance). Linking reorder_policy to input_catalog enforces approved input',
    `plant_id` BIGINT COMMENT 'Reference to the SAP plant or operational facility to which this reorder policy is scoped, enabling multi-site MRP planning.',
    `material_master_id` BIGINT COMMENT 'Reference to the inventory-managed material (seed, chemical, fertilizer, feed, or harvested commodity) for which this reorder policy applies.',
    `reorder_material_master_id` BIGINT COMMENT 'FK to inventory.material_master',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Reorder policies for seeds, agrochemicals, and feed are owned by a specific buyer or inventory planner. Procurement and inventory management processes require identifying the responsible employee for ',
    `storage_location_id` BIGINT COMMENT 'Reference to the storage location (grain bin, cold storage, warehouse, or field stockpile) where this reorder policy governs stock replenishment.',
    `supplier_assessment_id` BIGINT COMMENT 'Foreign key linking to quality.supplier_assessment. Business justification: Reorder policies in agriculture are quality-gated — suppliers with poor assessment scores require manual PO approval or reduced auto-replenishment. Linking reorder_policy to supplier_assessment enable',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Agriculture reorder policies execute replenishment against specific vendor contracts (contracted price, MOQ, lead time). Linking reorder_policy to vendor_contract ensures auto-PO creation uses contrac',
    `vendor_id` BIGINT COMMENT 'Reference to the preferred vendor/supplier from whom purchase requisitions should be sourced when this reorder policy triggers replenishment.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Seasonal reorder policies for seeds, fertilizers, and pesticides are calibrated by weather zone — peak season safety stock quantities and lead times differ by climate zone. Agriculture supply planners',
    `auto_po_creation` BOOLEAN COMMENT 'Indicates whether MRP-generated purchase requisitions for this material are automatically converted to purchase orders without manual buyer approval. Requires a valid source list and preferred supplier.',
    `buyer_group` STRING COMMENT 'SAP MM purchasing group (buyer group) responsible for processing purchase requisitions generated by this reorder policy. Determines routing and approval workflow for procurement.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this reorder policy record was first created in the system. Supports audit trail, data lineage, and SOX financial reporting controls.',
    `effective_date` DATE COMMENT 'Date from which this reorder policy configuration becomes active and is included in MRP planning runs. Supports seasonal policy activation and planned policy transitions.',
    `eoq` DECIMAL(18,2) COMMENT 'Optimal replenishment order quantity calculated to minimize total inventory holding and ordering costs. Expressed in primary UOM. Used as the fixed lot size in SAP MM MRP lot-sizing procedures.',
    `expiry_date` DATE COMMENT 'Date after which this reorder policy is no longer active. Null indicates an open-ended policy with no planned end date. Enables time-bound seasonal or campaign-specific replenishment configurations.',
    `goods_receipt_processing_days` STRING COMMENT 'Number of workdays required to process a goods receipt (GRN) after physical delivery, including quality inspection, weighing, and WMS putaway. Added to lead time in MRP net requirements calculation.',
    `is_hazmat` BOOLEAN COMMENT 'Indicates whether this material is classified as hazardous (e.g., pesticides, herbicides, fumigants). When true, EPA SDS requirements, REI (Restricted Entry Interval), and special storage/handling rules apply.',
    `is_mrp_active` BOOLEAN COMMENT 'Indicates whether this reorder policy is currently included in SAP MM MRP planning runs. When false, the policy exists as a configuration record but does not trigger automated purchase requisitions.',
    `is_regulated_substance` BOOLEAN COMMENT 'Indicates whether this material is subject to regulatory quantity limits, licensing, or reporting requirements (e.g., restricted-use pesticides under EPA, controlled fertilizers under APHIS). Triggers compliance workflow on purchase requisition.',
    `is_seasonal` BOOLEAN COMMENT 'Indicates whether this material experiences significant seasonal demand fluctuations (e.g., planting season seeds, harvest-time chemicals). When true, seasonal demand profiles are applied in MRP planning.',
    `last_reviewed_date` DATE COMMENT 'Date when this reorder policy was last reviewed and validated by the inventory planner or supply chain manager. Supports periodic policy governance and audit trail requirements.',
    `lead_time_days` STRING COMMENT 'Expected number of calendar days from purchase requisition creation to goods receipt at the storage location. Used by SAP MM MRP to calculate replenishment timing and avoid stockouts.',
    `lot_size_procedure` STRING COMMENT 'SAP MM MRP lot-sizing procedure that determines how replenishment quantities are calculated: fixed order quantity, lot-for-lot (exact requirement), EOQ, period-based, or min-max. Maps to SAP Lot Size field.. Valid values are `fixed|lot_for_lot|eoq|period_based|min_max`',
    `maximum_order_qty` DECIMAL(18,2) COMMENT 'Maximum quantity allowed per single purchase requisition to control procurement spend, storage capacity, and perishability risk. Expressed in primary UOM.',
    `maximum_stock_qty` DECIMAL(18,2) COMMENT 'Upper bound on inventory quantity for this material at this storage location. Replenishment orders will not exceed this level. Prevents overstocking and storage capacity violations.',
    `minimum_order_qty` DECIMAL(18,2) COMMENT 'Minimum quantity that must be ordered per purchase requisition, typically driven by supplier minimum order requirements or packaging constraints. Expressed in primary UOM.',
    `minimum_remaining_shelf_life_days` STRING COMMENT 'Minimum number of days of remaining shelf life required at time of goods receipt for the material to be accepted into stock. Rejects deliveries that do not meet this threshold per quality management policy.',
    `mrp_type` STRING COMMENT 'SAP MRP planning type that governs how replenishment is triggered: reorder point (ROP), time-phased planning, consumption-based, or manual. Directly maps to SAP MM MRP Type field (e.g., VB, VM, PD).. Valid values are `reorder_point|time_phased|consumption_based|manual`',
    `order_multiple_qty` DECIMAL(18,2) COMMENT 'Quantity increment by which replenishment orders must be rounded up (e.g., full pallet, full bin, full truckload). Ensures orders align with supplier packaging or transport unit constraints.',
    `peak_season_end_month` STRING COMMENT 'Calendar month (1–12) when peak seasonal demand ends for this material. Defines the seasonal window during which elevated reorder points and safety stock levels are applied.',
    `peak_season_safety_stock_qty` DECIMAL(18,2) COMMENT 'Elevated safety stock quantity applied during the defined peak season window (e.g., planting or harvest period). Overrides the standard safety stock quantity during peak months.',
    `peak_season_start_month` STRING COMMENT 'Calendar month (1–12) when peak seasonal demand begins for this material. Used to adjust reorder points and safety stock levels ahead of high-demand periods such as planting or harvest seasons.',
    `policy_number` STRING COMMENT 'Externally-known alphanumeric business identifier for this reorder policy record, used in SAP MM MRP planning runs and cross-system references.. Valid values are `^RP-[A-Z0-9]{4,20}$`',
    `policy_status` STRING COMMENT 'Current lifecycle status of the reorder policy configuration. Only active policies are evaluated during SAP MM MRP planning runs.. Valid values are `active|inactive|draft|under_review|suspended`',
    `procurement_type` STRING COMMENT 'Indicates whether the material is procured externally (purchased from supplier), produced in-house, or both. Drives SAP MM MRP to generate purchase requisitions vs. planned orders.. Valid values are `external|in_house|both`',
    `purchasing_organization` STRING COMMENT 'SAP purchasing organization responsible for negotiating and executing supply contracts for this material. Defines the legal and organizational entity that issues purchase orders.',
    `reorder_point_qty` DECIMAL(18,2) COMMENT 'Stock level threshold at which a purchase requisition is automatically triggered in SAP MM MRP. Expressed in the primary unit of measure (CWT, BU, or MT). When on-hand quantity falls to or below this value, replenishment is initiated.',
    `rotation_method` STRING COMMENT 'Inventory rotation method applied to this material: FIFO (First In First Out), FEFO (First Expired First Out), LIFO (Last In First Out), or manual. FEFO is mandatory for perishable commodities and chemicals with expiration dates per FSMA and HACCP requirements.. Valid values are `FIFO|FEFO|LIFO|manual`',
    `safety_stock_qty` DECIMAL(18,2) COMMENT 'Minimum buffer stock quantity maintained to protect against demand variability and supply lead time uncertainty. Expressed in primary UOM. Corresponds to SAP MM Safety Stock field in MRP 2 view.',
    `shelf_life_days` STRING COMMENT 'Maximum number of days this material can be stored before it expires or degrades below acceptable quality standards. Used to enforce FEFO rotation and calculate expiration dates from goods receipt date.',
    `storage_condition` STRING COMMENT 'Required storage environment for this material. Drives assignment to compatible storage locations (e.g., cold storage for perishables, hazmat-certified bins for chemicals). [ENUM-REF-CANDIDATE: ambient|refrigerated|frozen|controlled_atmosphere|dry|hazmat — promote to reference product]. Valid values are `ambient|refrigerated|frozen|controlled_atmosphere|dry|hazmat`',
    `uom_primary` STRING COMMENT 'Primary unit of measure in which all quantity thresholds (reorder point, safety stock, maximum stock, EOQ) are expressed. Supports CWT (hundredweight), BU (bushel), and MT (metric ton) per agricultural inventory standards. [ENUM-REF-CANDIDATE: CWT|BU|MT|LB|KG|GAL|L|EA — 8 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this reorder policy record was last modified. Used for change detection in downstream MRP planning runs and data pipeline incremental loads.',
    CONSTRAINT pk_reorder_policy PRIMARY KEY(`reorder_policy_id`)
) COMMENT 'Master configuration record defining reorder and replenishment policies for inventory-managed materials including seeds, chemicals, fertilizers, and feed. Captures material, storage location, reorder point quantity, safety stock level in CWT/BU/MT, maximum stock level, economic order quantity (EOQ), lead time days, preferred supplier reference, and seasonal demand flag. Drives automated purchase requisition creation in SAP MM MRP.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`warehouse_task` (
    `warehouse_task_id` BIGINT COMMENT 'Unique surrogate identifier for each warehouse task record in the Silver Layer lakehouse. Primary key for the warehouse_task data product. Role: TRANSACTION_HEADER.',
    `asset_id` BIGINT COMMENT 'Reference to the material handling equipment (forklift, reach truck, conveyor, pallet jack) assigned to execute this task. Supports equipment utilization tracking and OEE (Overall Equipment Effectiveness) measurement.',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the inventory lot (LOT/GRN batch) being moved or counted in this task. Supports FIFO/FEFO rotation enforcement and full traceability from farm to table per FSMA requirements.',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Grain handling, bin transfers, and input picking tasks in agriculture are routinely assigned to and executed by crews, not just individuals. Labor cost allocation by crew, crew productivity reporting,',
    `delivery_order_id` BIGINT COMMENT 'Foreign key linking to sales.delivery_order. Business justification: WMS-to-commercial execution: warehouse tasks (pick, stage, load) are executed to fulfill delivery orders. This FK links physical warehouse execution to the commercial delivery obligation, enabling del',
    `employee_id` BIGINT COMMENT 'Reference to the warehouse operator (workforce member) assigned to execute this task. PARTY_REFERENCE for this TRANSACTION_HEADER. Used for labor productivity tracking, OEE measurement, and workforce planning via SAP SuccessFactors integration.',
    `goods_issue_id` BIGINT COMMENT 'Foreign key linking to inventory.goods_issue. Business justification: A goods_issue triggers picking warehouse tasks in WMS. Adding goods_issue_id FK (nullable) to warehouse_task links picking tasks to the originating goods issue, enabling pick-to-issue completion track',
    `inbound_plan_id` BIGINT COMMENT 'Foreign key linking to supply.inbound_plan. Business justification: WMS put-away tasks are created to execute inbound plans — when a planned inbound arrives, warehouse tasks are generated for unloading, inspection, and bin placement. Linking warehouse_task to inbound_',
    `inventory_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to inventory.goods_receipt. Business justification: A goods_receipt triggers putaway warehouse tasks in Manhattan Associates WMS. Adding goods_receipt_id FK (nullable) to warehouse_task links putaway tasks to the originating receipt, enabling GR-to-put',
    `load_plan_id` BIGINT COMMENT 'Foreign key linking to supply.load_plan. Business justification: WMS picking and staging tasks are created to execute outbound load plans. Linking warehouse_task to load_plan enables task completion to update load plan status, supports loading sequence management, ',
    `plant_id` BIGINT COMMENT 'Reference to the SAP S/4HANA MM plant (facility/warehouse site) where this task is executed. Links the task to the physical agricultural storage facility such as a grain elevator, cold storage facility, or distribution warehouse.',
    `material_master_id` BIGINT COMMENT 'Reference to the agricultural material (seed, chemical, fertilizer, or harvested commodity) that is the subject of this warehouse task. Aligns with SAP S/4HANA MM material master.',
    `bin_location_id` BIGINT COMMENT 'Foreign key linking to inventory.bin_location. Business justification: warehouse_task has source_bin (STRING) as a denormalized WMS bin reference for the pick/source location. WMS tasks operate at bin level — adding source_bin_location_id FK links to the bin_location mas',
    `stock_reservation_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_reservation. Business justification: warehouse_task can be triggered by a stock_reservation (picking task to fulfill a reservation for production, sales, or field application). Adding stock_reservation_id FK (nullable) links the task to ',
    `stock_transfer_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_transfer. Business justification: warehouse_task has reference_document_number (STRING) and reference_document_type (STRING) as polymorphic references. A stock_transfer generates multiple warehouse tasks (pick from source bin, putaway',
    `storage_location_id` BIGINT COMMENT 'Reference to the storage location (warehouse zone or area) within the plant where this task is scoped. Aligns with SAP S/4HANA MM storage location and Manhattan Associates WMS location hierarchy.',
    `assigned_timestamp` TIMESTAMP COMMENT 'Date and time when this task was assigned to a specific warehouse operator in WMS. Used to calculate queue wait time (time from creation to assignment) as a labor management KPI.',
    `cancellation_reason` STRING COMMENT 'Free-text or coded reason provided when a task is cancelled before completion (e.g., material not found, bin location error, order cancelled, system error). Populated only when task_status = cancelled. Supports root cause analysis for operational improvement.',
    `completion_timestamp` TIMESTAMP COMMENT 'Date and time when the warehouse operator confirmed task completion in WMS. Used to calculate execution duration, throughput rates, and SLA compliance. Null if task is not yet completed or was cancelled.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this warehouse task was created in Manhattan Associates WMS. RECORD_AUDIT_CREATED for this TRANSACTION_HEADER. Also serves as the BUSINESS_EVENT_TIMESTAMP representing when the operational need was identified. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `destination_bin` STRING COMMENT 'WMS bin address (aisle-bay-level-position) to which the material is to be placed or transferred. Corresponds to the destination bin field in Manhattan Associates WMS task management. Used for putaway optimization and bin capacity planning.',
    `equipment_type` STRING COMMENT 'Category of material handling equipment used for this task. Drives labor standard calculations, aisle access rules, and capacity planning. Forklift and reach truck are common in grain elevator and cold storage environments.. Valid values are `forklift|reach_truck|pallet_jack|conveyor|hand_scanner|autonomous_vehicle`',
    `execution_duration_seconds` STRING COMMENT 'Elapsed time in seconds between task start and task completion. Sourced directly from Manhattan Associates WMS task management (not derived in the Silver Layer). Used for labor standard comparison, operator productivity benchmarking, and warehouse KPI reporting.',
    `grn_number` STRING COMMENT 'Goods Receipt Note (GRN) number associated with the inbound receipt that created the inventory being handled in this task. Provides traceability back to the original receiving event in SAP S/4HANA MM.',
    `is_cycle_count_discrepancy` BOOLEAN COMMENT 'Indicates whether this cycle count task resulted in a quantity discrepancy between the WMS system quantity and the physically counted quantity. When true, triggers an inventory adjustment workflow in SAP S/4HANA MM and may require supervisor approval.',
    `is_hazardous` BOOLEAN COMMENT 'Indicates whether the material involved in this task is classified as hazardous (e.g., pesticides, herbicides, fumigants with EPA/SDS requirements). When true, triggers special handling protocols, REI (Restricted Entry Interval) enforcement, and SDS documentation requirements.',
    `is_temperature_controlled` BOOLEAN COMMENT 'Indicates whether this task involves temperature-controlled storage (cold storage, refrigerated warehouse). When true, operator must follow cold chain handling procedures and temperature monitoring requirements per FDA and FSMA cold chain rules.',
    `priority` STRING COMMENT 'Numeric priority ranking assigned by WMS to determine task execution sequence. Lower values indicate higher urgency. Used by warehouse management to sequence operator workloads and meet order fulfillment SLAs. Typically ranges 1 (highest) to 99 (lowest) per Manhattan Associates WMS configuration.',
    `qty_confirmed` DECIMAL(18,2) COMMENT 'Actual quantity of material confirmed by the operator upon task completion. May differ from qty_required due to short picks, partial putaways, or cycle count discrepancies. Drives inventory adjustment postings in SAP S/4HANA MM.',
    `qty_required` DECIMAL(18,2) COMMENT 'Quantity of material required to be moved, counted, or processed as specified when the task was created. Expressed in the primary unit of measure (UOM) for the material. QUANTITATIVE_RESULT for this non-monetary transaction.',
    `qty_variance` DECIMAL(18,2) COMMENT 'Difference between qty_required and qty_confirmed (qty_required minus qty_confirmed). Positive value indicates a short pick or under-count; negative value indicates an over-pick or over-count. Used for shrinkage analysis and inventory accuracy KPI reporting.',
    `reference_document_number` STRING COMMENT 'Source document number that triggered this task, such as a SAP Sales Order (SO), Purchase Order (PO), Transfer Order, or Goods Receipt Note (GRN). Provides end-to-end traceability from business document to physical warehouse execution.',
    `reference_document_type` STRING COMMENT 'Type of source document that triggered this task. SO=Sales Order, PO=Purchase Order, GRN=Goods Receipt Note, TO=Transfer Order, RO=Return Order, CC=Cycle Count authorization. Enables filtering and reporting by business process origin.. Valid values are `SO|PO|GRN|TO|RO|CC`',
    `rotation_method` STRING COMMENT 'Inventory rotation rule applied when selecting the source lot for this task. FIFO (First In First Out) is standard for most agricultural commodities; FEFO (First Expired First Out) is applied for perishables and inputs with PHI (Pre-Harvest Interval) constraints. Ensures compliance with food safety and quality standards.. Valid values are `FIFO|FEFO|LIFO|LEFO`',
    `sap_transfer_order_number` STRING COMMENT 'SAP S/4HANA WM/EWM transfer order number corresponding to this WMS task. Enables reconciliation between Manhattan Associates WMS task execution and SAP inventory postings for financial and inventory accuracy reporting.',
    `standard_time_seconds` STRING COMMENT 'Engineered labor standard time in seconds for this task type and material/distance combination, as configured in Manhattan Associates WMS labor management. Used to calculate labor efficiency ratio (actual vs. standard) for OEE and workforce productivity reporting.',
    `start_timestamp` TIMESTAMP COMMENT 'Date and time when the warehouse operator began executing this task (scanned first location or confirmed task start in WMS). Used to calculate actual execution duration and labor productivity metrics.',
    `task_group` STRING COMMENT 'WMS task group or wave identifier that bundles multiple related tasks for coordinated execution (e.g., a picking wave for a sales order shipment or a cycle count batch). Corresponds to the Task Group field in Manhattan Associates WMS.',
    `task_number` STRING COMMENT 'Externally-known WMS-generated alphanumeric task identifier used by warehouse operators and supervisors to reference a specific task in Manhattan Associates WMS. Serves as the BUSINESS_IDENTIFIER for this transaction. Corresponds to the Task ID field in Manhattan Associates WMS task management module.',
    `task_status` STRING COMMENT 'Current lifecycle state of the warehouse task as tracked in Manhattan Associates WMS. LIFECYCLE_STATUS for this TRANSACTION_HEADER. open=task created and awaiting assignment; in_progress=operator has accepted and started execution; confirmed=task completed and confirmed in WMS; cancelled=task voided before completion; on_hold=task paused pending resolution.. Valid values are `open|in_progress|confirmed|cancelled|on_hold`',
    `task_type` STRING COMMENT 'Classification of the physical warehouse activity to be performed. Drives labor routing, equipment assignment, and productivity measurement. Values: putaway (inbound stock placement), picking (outbound order fulfillment), replenishment (bin restocking), consolidation (combining partial loads), relabeling (label correction/update), cycle_count (physical inventory verification per WMS cycle count schedule).. Valid values are `putaway|picking|replenishment|consolidation|relabeling|cycle_count`',
    `uom` STRING COMMENT 'Unit of measure in which task quantities (qty_required, qty_confirmed) are expressed. Agricultural commodities use industry-standard units: CWT (Hundredweight), BU (Bushel), MT (Metric Ton). Inputs such as seed and chemicals may use KG, LB, EA, CS, or BAG. [ENUM-REF-CANDIDATE: CWT|BU|MT|KG|LB|EA|CS|BAG — 8 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this warehouse task record was last modified in the source WMS or Silver Layer. RECORD_AUDIT_UPDATED for this TRANSACTION_HEADER. Tracks status changes, reassignments, and quantity corrections.',
    `wave_number` STRING COMMENT 'Outbound wave release number that triggered this picking or replenishment task. Links the task to a specific order fulfillment wave in Manhattan Associates WMS, enabling wave-level productivity and throughput analysis.',
    `wms_task_number` STRING COMMENT 'Native task identifier from Manhattan Associates WMS source system. Preserved for cross-system reconciliation and audit trail between the Silver Layer lakehouse and the operational WMS. Distinct from the surrogate warehouse_task_id.',
    CONSTRAINT pk_warehouse_task PRIMARY KEY(`warehouse_task_id`)
) COMMENT 'WMS-generated operational task record for physical warehouse activities including putaway, picking, replenishment, consolidation, relabeling, and cycle count execution. Captures task number, task type, assigned operator, source bin, destination bin, material, lot, quantity, task status (open, in-progress, confirmed, cancelled), priority, creation timestamp, completion timestamp, and execution duration. Sourced from Manhattan Associates WMS task management. Supports warehouse labor productivity tracking and operational efficiency measurement.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`quarantine_hold` (
    `quarantine_hold_id` BIGINT COMMENT 'Unique system-generated identifier for each quarantine hold record. Primary key for the quarantine_hold data product in the inventory domain.',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the specific inventory lot or batch under quarantine hold. Supports FIFO/FEFO rotation and lot-level traceability per FSMA requirements.',
    `protection_event_id` BIGINT COMMENT 'Foreign key linking to crop.protection_event. Business justification: A quarantine hold on a commodity lot may be triggered by a crop protection event with PHI violation or MRL exceedance. Linking quarantine_hold to protection_event supports PHI compliance tracking, MRL',
    `employee_id` BIGINT COMMENT 'SAP user ID or employee identifier of the authorized quality manager or regulatory officer who approved the final disposition decision. Required for GFSI, SQF, BRC, and FSMA preventive controls documentation.',
    `inspection_record_id` BIGINT COMMENT 'Foreign key linking to compliance.inspection_record. Business justification: Regulatory inspections (FDA, USDA) directly trigger inventory quarantine holds in agriculture. The quarantine_hold has initiating_event_type/reference as plain text but no FK to the inspection_record ',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: MRL exceedance is a primary cause of quarantine holds in agriculture. Linking to mrl_threshold enables regulatory disposition decisions, FDA/USDA audit trails, and dynamic compliance checking as toler',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Inventory quarantine holds are initiated by quality nonconformance events (MRL exceedance, failed inspection). quarantine_hold has initiating_event_reference (plain text) but no typed FK. Direct nonco',
    `recall_event_id` BIGINT COMMENT 'Foreign key linking to compliance.recall_event. Business justification: Recall events directly trigger inventory quarantine holds in agriculture food safety operations. The quarantine_hold has is_recall_related and recall_class as plain text denormalization. A direct FK t',
    `regulatory_finding_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_finding. Business justification: MRL exceedances and pesticide regulatory findings directly trigger commodity quarantine holds. The quarantine_hold already tracks mrl_exceedance_substance/level as denormalized fields. Linking to regu',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to supply.shipment. Business justification: Quarantine holds are frequently initiated based on shipment-level events (temperature excursion during transit, customs inspection hold, MRL exceedance detected at port). Linking quarantine_hold to sh',
    `stock_position_id` BIGINT COMMENT 'Reference to the parent stock position record in the inventory SSOT from which this quarantine hold was initiated.',
    `storage_location_id` BIGINT COMMENT 'Reference to the storage location (grain bin, cold storage, warehouse, field stockpile) where the quarantined inventory is physically held.',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Frost alerts trigger quarantine holds on frost-damaged harvested grain — a named food safety and quality process. The quarantine_hold has untyped initiating_event_reference; a typed FK to frost_alert ',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Hail and flood precipitation events trigger quarantine holds on commodity lots (hail-damaged grain, flood-contaminated storage). This typed FK supports insurance claim documentation and FSMA food safe',
    `alert_id` BIGINT COMMENT 'Foreign key linking to weather.weather_alert. Business justification: Severe weather alerts (tornado, flood, extreme heat) trigger quarantine holds on inventory at affected storage locations. Typed FK to weather_alert supports weather-triggered quarantine traceability',
    `actual_release_date` DATE COMMENT 'The actual calendar date on which the quarantine hold was resolved and the inventory was either released for use, reworked, destroyed, or returned. Null until disposition is executed.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the quarantine hold record was first created in the system. Audit trail field for data lineage, SOX compliance, and regulatory investigation timelines.',
    `disposition_decision` STRING COMMENT 'Final disposition decision made by the quality or regulatory authority for the quarantined inventory. Release: cleared for normal use; Rework: requires reprocessing before use; Destroy: condemned and disposed; Return: returned to supplier; Donate: donated to approved channel; Regrade: reclassified to lower grade.. Valid values are `release|rework|destroy|return|donate|regrade`',
    `disposition_notes` STRING COMMENT 'Free-text narrative documenting the rationale for the disposition decision, corrective actions taken, and any conditions attached to the release or destruction of the quarantined inventory.',
    `expected_release_date` DATE COMMENT 'Anticipated date by which the quarantine hold investigation is expected to be completed and the inventory released or dispositioned. Used for supply chain continuity planning and customer commitment management.',
    `grn_number` STRING COMMENT 'Goods Receipt Note number from SAP MM goods receipt posting that originated the inventory lot now under quarantine hold. Enables traceability back to the inbound supply chain event.',
    `hold_number` STRING COMMENT 'Externally-known, human-readable business identifier for the quarantine hold record. Used in SAP QM usage decisions, WMS hold tags, and regulatory correspondence. Format: QH-{YYYY}-{NNNNNN}.. Valid values are `^QH-[0-9]{4}-[0-9]{6}$`',
    `hold_reason` STRING COMMENT 'Detailed narrative description of the specific reason the quarantine hold was initiated. Captures the triggering event such as COA failure, HACCP critical limit deviation, MRL exceedance, foreign material detection, or customer complaint details.',
    `hold_start_date` DATE COMMENT 'The calendar date on which the quarantine hold was officially initiated and the inventory was blocked in SAP QM and WMS. Principal business event date for the hold lifecycle.',
    `hold_status` STRING COMMENT 'Current lifecycle state of the quarantine hold record. Drives SAP QM usage decision workflow and WMS inventory blocking. Open: hold initiated; Under_review: quality/regulatory investigation in progress; Pending_disposition: investigation complete, awaiting disposition approval; Released: stock cleared for use; Closed: disposition executed; Escalated: elevated to regulatory authority.. Valid values are `open|under_review|pending_disposition|released|closed|escalated`',
    `hold_type` STRING COMMENT 'Classification of the quarantine hold by its initiating business reason. Drives workflow routing and regulatory notification requirements. Values: quality (COA failure, specification deviation), regulatory (USDA/FDA/EPA review), safety (HACCP deviation, food safety risk), recall (voluntary or mandatory recall), customer_complaint (trade partner complaint), environmental (EPA/ISO 14001 contamination concern).. Valid values are `quality|regulatory|safety|recall|customer_complaint|environmental`',
    `initiated_by` STRING COMMENT 'SAP user ID or employee identifier of the person who initiated the quarantine hold. Required for audit trail, SOX compliance, and regulatory investigation documentation.',
    `initiating_event_reference` STRING COMMENT 'External reference number of the document or event that triggered the hold, such as a COA (Certificate of Analysis) number, HACCP deviation report number, EU RASFF notification number, FDA recall number, or internal audit finding ID.',
    `initiating_event_type` STRING COMMENT 'Categorical classification of the specific triggering event that caused the quarantine hold to be raised. Supports root cause analysis and regulatory reporting. [ENUM-REF-CANDIDATE: coa_failure|haccp_deviation|mrl_exceedance|foreign_material|microbiological|allergen|labeling|supplier_notification|regulatory_alert|customer_complaint|internal_audit — promote to reference product]',
    `is_recall_related` BOOLEAN COMMENT 'Indicates whether this quarantine hold is associated with a formal product recall (voluntary or mandatory). True triggers recall response procedures per FDA FSMA and USDA FSIS recall protocols.',
    `lot_number` STRING COMMENT 'Batch or lot number assigned at goods receipt (GRN) or production. Supports lot-level traceability for recall response and HACCP deviation investigation.',
    `material_number` STRING COMMENT 'SAP material number (alphanumeric) identifying the commodity or input material under hold. Denormalized from material master for operational reporting without join dependency.',
    `mrl_detected_level` DECIMAL(18,2) COMMENT 'Measured concentration of the residue substance detected in the sample, expressed in mg/kg (ppm). Compared against the applicable MRL threshold to determine exceedance. Null if hold is not MRL-related.',
    `mrl_exceedance_substance` STRING COMMENT 'Name of the pesticide active ingredient (AI) or chemical substance that exceeded the Maximum Residue Limit (MRL) as defined by EPA or EU Regulation 396/2005, triggering the quarantine hold. Null if hold is not MRL-related.',
    `phi_days_remaining` STRING COMMENT 'Number of days remaining in the Pre-Harvest Interval (PHI) at the time the hold was initiated. A positive value indicates the crop was harvested before the PHI elapsed, which may be the root cause of an MRL exceedance hold.',
    `qty_on_hold_bu` DECIMAL(18,2) COMMENT 'Quantity of inventory placed under quarantine hold expressed in bushels (BU). Standard unit for grain commodities (corn, soybeans, wheat) in US agricultural trade and USDA WASDE reporting.',
    `qty_on_hold_cwt` DECIMAL(18,2) COMMENT 'Quantity of inventory placed under quarantine hold expressed in hundredweight (CWT). Primary unit for grain and commodity inventory valuation and trading in US agricultural markets.',
    `qty_on_hold_mt` DECIMAL(18,2) COMMENT 'Quantity of inventory placed under quarantine hold expressed in metric tons (MT). Required for international trade documentation, EU regulatory reporting, and Codex Alimentarius compliance.',
    `regulatory_notification_date` DATE COMMENT 'Date on which the regulatory authority (FDA, USDA, EPA, EU RASFF) was formally notified of the quarantine hold or food safety event. Required for FSMA compliance documentation and EU RASFF reporting timelines.',
    `regulatory_notification_required` BOOLEAN COMMENT 'Indicates whether this quarantine hold requires mandatory notification to a regulatory authority (FDA, USDA FSIS, EPA, EU RASFF). True when the hold involves a food safety risk, MRL exceedance, or mandatory recall trigger.',
    `regulatory_reference_number` STRING COMMENT 'Official reference number assigned by the regulatory authority (FDA recall number, USDA FSIS case number, EU RASFF notification number, EPA enforcement action number) for tracking the regulatory response to this hold.',
    `sap_qm_inspection_lot` STRING COMMENT 'SAP QM inspection lot number associated with this quarantine hold. Links the hold to the formal quality inspection process and usage decision workflow in SAP S/4HANA QM module.',
    `sap_qm_usage_decision` STRING COMMENT 'SAP QM usage decision code recorded at inspection lot closure. A=Accept (release to unrestricted stock), R=Reject (block/destroy), B=Return to vendor, S=Sort/rework. Drives automatic stock transfer posting in SAP MM.. Valid values are `A|R|B|S`',
    `uom_primary` STRING COMMENT 'The primary unit of measure used for inventory valuation and SAP MM stock management for this quarantine hold record. Determines which quantity field is the authoritative measure for disposition and reporting. [ENUM-REF-CANDIDATE: CWT|BU|MT|KG|LB|EA|CS — 7 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the quarantine hold record. Supports change tracking, audit trail requirements, and Databricks Silver Layer incremental processing.',
    `wms_hold_tag_number` STRING COMMENT 'Physical hold tag or WMS blocking record number assigned by Manhattan Associates WMS to identify and segregate the quarantined inventory in the warehouse or storage facility.',
    CONSTRAINT pk_quarantine_hold PRIMARY KEY(`quarantine_hold_id`)
) COMMENT 'Transactional record managing inventory holds and quarantine status for lots or stock positions pending quality inspection, regulatory review, or food safety investigation. Captures hold number, material, lot, location, quantity on hold in CWT/BU/MT, hold type (quality, regulatory, safety, recall, customer_complaint), hold reason, initiating event reference (COA failure, HACCP deviation, MRL exceedance per EPA/EU Regulation 396/2005), hold start date, expected release date, actual release date, disposition decision (release, rework, destroy, return), and approver. Integrates with SAP QM usage decision and supports FDA/USDA recall response procedures, EU RASFF (Rapid Alert System for Food and Feed) notifications, and Codex Alimentarius food safety standards.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`approved_vendor_material` (
    `approved_vendor_material_id` BIGINT COMMENT 'Primary key for the approved_vendor_material association',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to the material master record for which this vendor is approved to supply',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to the approved vendor master record for this material sourcing relationship',
    `approved_status` STRING COMMENT 'Current qualification status of this vendor for supplying this specific material. Drives procurement system sourcing eligibility checks. Distinct from the vendor-level qualification_status on the vendor master, as a vendor may be globally approved but conditionally approved for a specific material category.',
    `contracted_price` DECIMAL(18,2) COMMENT 'Negotiated contracted price per base unit of measure for this vendor-material combination. Cannot reside on material_master (price varies by vendor) nor on vendor (price varies by material). Expressed in the vendors invoicing currency.',
    `lead_time_days` STRING COMMENT 'Vendor-specific lead time in calendar days from purchase order placement to expected delivery for this material. Relationship-specific — the same vendor may have different lead times for different materials.',
    `min_order_qty` DECIMAL(18,2) COMMENT 'Minimum order quantity (in the materials base UOM) required by this vendor for this material. Relationship-specific commercial term that varies by vendor-material combination.',
    `preferred_rank` STRING COMMENT 'Numeric ranking of this vendors preference for sourcing this material (1 = primary/preferred source, 2 = secondary, etc.). Used by procurement to determine sourcing priority when multiple approved vendors exist for the same material.',
    `qualification_date` DATE COMMENT 'Date on which this vendor was approved to supply this specific material. Relationship-specific — a vendor may be qualified for different materials on different dates.',
    CONSTRAINT pk_approved_vendor_material PRIMARY KEY(`approved_vendor_material_id`)
) COMMENT 'This association product represents the Approved Vendor List (AVL) contract between material_master and vendor. It captures the operational qualification and commercial terms governing each approved vendor-material sourcing relationship in agricultural procurement. Each record links one material to one approved vendor and carries attributes — qualification status, preferred rank, contracted price, lead time, and minimum order quantity — that exist only in the context of this specific vendor-material pairing and cannot reside on either the material master or the vendor master alone.. Existence Justification: In agricultural procurement, a single material (e.g., glyphosate herbicide, hybrid corn seed, urea fertilizer) is routinely sourced from multiple approved vendors at different contracted prices, lead times, and minimum order quantities — and each vendor supplies many different materials. The business actively manages an Approved Vendor List (AVL) per material, tracking qualification status, preferred ranking, contracted pricing, and lead times for each vendor-material combination. This is a well-recognized operational concept in agriculture procurement that procurement teams create, update, and retire as supply agreements change.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`lot_allocation` (
    `lot_allocation_id` BIGINT COMMENT 'Primary key for the lot_allocation association',
    `account_id` BIGINT COMMENT 'Foreign key linking this allocation record to the customer account receiving the committed commodity quantity.',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking this allocation record to the specific commodity lot from which quantity is being committed.',
    `allocated_quantity_bu` DECIMAL(18,2) COMMENT 'The quantity of the commodity lot committed to this customer account under this allocation, expressed in bushels. This value belongs to the allocation relationship — not to the lot (which tracks total on-hand) nor to the account (which does not own inventory).',
    `allocation_date` DATE COMMENT 'The date on which this allocation was created and committed, recording when the business decision to assign this lot quantity to this account was made. Used for FIFO/FEFO rotation audit trails and forward contract settlement timing.',
    `allocation_status` STRING COMMENT 'Current lifecycle status of this lot-to-account allocation. Drives fulfillment workflow: PENDING (created, awaiting confirmation), CONFIRMED (customer accepted), SHIPPED (quantity dispatched), INVOICED (billing complete), CANCELLED (allocation voided), ON_HOLD (suspended pending quality or compliance review).',
    `contract_reference` STRING COMMENT 'The forward contract number, sales order number, or purchase agreement identifier governing this allocation. Links the allocation to the originating commercial agreement. May reference a SAP SD sales order or an external grain trading platform contract ID.',
    `price_per_bu` DECIMAL(18,2) COMMENT 'The negotiated or contracted price per bushel for this specific lot-account allocation. Price varies by deal, contract terms, and market conditions — it belongs to the allocation, not to the lot (which has no single price) nor to the account (which has no per-lot price).',
    CONSTRAINT pk_lot_allocation PRIMARY KEY(`lot_allocation_id`)
) COMMENT 'This association product represents the Contract between commodity_lot and account in the agricultural commodity trading process. It captures the operational commitment of a specific quantity from a commodity lot to a customer account, typically governed by a forward contract or sales order. Each record links one commodity_lot to one account with attributes — allocated quantity, price, status, and contract reference — that exist only in the context of this allocation relationship and cannot reside on either the lot or the account alone.. Existence Justification: In agricultural commodity trading, a single commodity lot is routinely split and allocated to multiple customer accounts (e.g., a 50,000 bu corn lot sold in portions to three food manufacturers under separate forward contracts), and a customer account simultaneously holds allocations across many commodity lots. The business actively manages these allocations as operational records — creating, updating, and cancelling them — with quantity, price, status, and contract reference data that belongs to neither the lot nor the account alone. This is a recognized operational concept in grain trading known as a Lot Allocation or Commodity Allocation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`lot_fulfillment` (
    `lot_fulfillment_id` BIGINT COMMENT 'Primary key for the lot_fulfillment association',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to the commodity lot being allocated or fulfilled against this delivery order',
    `delivery_order_id` BIGINT COMMENT 'Foreign key linking to the delivery order that this commodity lot (or portion thereof) is fulfilling',
    `lot_number` STRING COMMENT 'Batch or lot tracking identifier assigned to the commodity in this delivery. Enables end-to-end traceability from farm origin through customer delivery for FSMA compliance and recall management. [Moved from delivery_order: The lot_number string on delivery_order is a denormalized reference that can only capture a single lot per delivery order. In the true M:N business reality, a delivery order is fulfilled by multiple lots. This field should be removed from delivery_order and replaced by the lot_fulfillment association, which properly links delivery_order to multiple commodity_lot records via commodity_lot_id (which carries lot_number as an attribute).]',
    `lot_split_pct` DECIMAL(18,2) COMMENT 'The percentage of the total commodity lot quantity allocated to this specific delivery order. Supports FIFO/FEFO rotation tracking and lot consumption reporting when a single lot is split across multiple delivery orders.',
    `moisture_at_delivery` DECIMAL(18,2) COMMENT 'The moisture content percentage of this commodity lot measured at the time of delivery for this specific delivery order. Used for shrinkage calculation, quality settlement, and FSMA traceability. Distinct from the lots master moisture_content_pct which reflects the moisture at receipt.',
    `quality_grade_at_delivery` STRING COMMENT 'The USDA or contractually specified quality grade confirmed for this specific lot at the time of delivery. May differ from the lots master grade if re-grading occurred at load-out. Belongs to the lot-delivery pairing, not to either entity alone, and is used for quality settlement and contract compliance.',
    `quantity_allocated_bu` DECIMAL(18,2) COMMENT 'The quantity of this commodity lot allocated to this specific delivery order, expressed in bushels. Represents the planned commitment of lot inventory to the delivery at the time of allocation. Cannot reside on commodity_lot (which tracks total on-hand) or delivery_order (which tracks total ordered quantity) alone.',
    `quantity_delivered_bu` DECIMAL(18,2) COMMENT 'The actual quantity of this commodity lot that was physically delivered against this delivery order, expressed in bushels. May differ from quantity_allocated_bu due to scale tickets, shrinkage, or load adjustments. Used for quality settlement and inventory depletion.',
    CONSTRAINT pk_lot_fulfillment PRIMARY KEY(`lot_fulfillment_id`)
) COMMENT 'This association product represents the fulfillment event between a commodity_lot and a delivery_order in the agricultural supply chain. It captures the operational allocation of a specific commodity lot (or portion thereof) to a specific delivery order, recording quantity allocated, quantity actually delivered, lot split percentage, and quality measurements (grade and moisture) confirmed at the time of delivery. Each record links one commodity_lot to one delivery_order and carries attributes that exist only in the context of this specific lot-to-delivery pairing, supporting FSMA Section 204 traceability, quality settlement, and FIFO/FEFO rotation compliance.. Existence Justification: In grain trading and agricultural supply chain operations, a single delivery order is routinely fulfilled by blending or splitting multiple commodity lots (e.g., combining two partial bins of corn to meet a 50,000 BU delivery order), and a single commodity lot can be allocated across multiple delivery orders over time (e.g., a large 100,000 BU lot split across three separate customer deliveries). The business actively manages this lot-to-delivery allocation as an operational record — tracking quantity allocated, quality at delivery, and moisture per lot-delivery combination — for FSMA Section 204 traceability, quality settlement, and regulatory compliance. This is a recognized operational concept in grain merchandising known as lot allocation or lot fulfillment, with its own data (quantity_allocated_bu, moisture_at_delivery, quality_grade_at_delivery) that belongs to neither the lot nor the delivery order alone.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`inventory`.`lot_pesticide_exposure` (
    `lot_pesticide_exposure_id` BIGINT COMMENT 'Primary key for the lot_pesticide_exposure association',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to the commodity lot whose PHI compliance status is being determined by this pesticide application exposure record.',
    `pesticide_use_record_id` BIGINT COMMENT 'Foreign key linking to the pesticide use record (PUR) that generated this exposure event for the associated commodity lot.',
    `active_ingredient_name` STRING COMMENT 'The active ingredient (AI) of the pesticide product as it applies to this lots exposure record. Captured at the association level to support MRL (Maximum Residue Limit) checks and export compliance queries per lot without requiring a join to the PUR. Sourced from detection phase relationship data.',
    `application_date` DATE COMMENT 'The date of the pesticide application as it pertains to this specific lots PHI compliance calculation. Sourced from the detection phase relationship data. Denormalized here to support lot-level PHI window calculations without requiring a join back to the PUR.',
    `application_rate` DECIMAL(18,2) COMMENT 'The application rate of the pesticide product relevant to this lots exposure. Captured at the association level to support residue estimation and MRL compliance checks per lot. Sourced from detection phase relationship data.',
    `area_treated` DECIMAL(18,2) COMMENT 'The portion of the total treated area that is attributable to this specific commodity lot. A single application may cover an entire field, but individual lots may represent sub-parcels or harvest windows within that field. Sourced from detection phase relationship data.',
    `exposure_determination_method` STRING COMMENT 'The method by which this lot was determined to be exposed to this pesticide application — e.g., via GIS field boundary overlap, manual agronomist assignment, or system-derived parcel matching. Required for audit trail and regulatory defensibility.',
    `phi_clearance_date` DATE COMMENT 'The earliest date on which this commodity lot may be harvested while remaining compliant with the PHI for this specific pesticide application. Calculated as application_date + phi_days from the associated PUR. This derived date belongs to the association because it is specific to the lot-application pairing.',
    `phi_compliant_flag` BOOLEAN COMMENT 'Indicates whether the commodity lots actual or projected harvest date satisfies the Pre-Harvest Interval (PHI) requirement for this specific pesticide application. This flag belongs to the association because the same PUR may be PHI-compliant for one lot (harvested later) and non-compliant for another (harvested earlier).',
    `phi_date` DATE COMMENT 'The Pre-Harvest Interval (PHI) date — the earliest date on which the commodity could have been legally harvested after the last pesticide or chemical application, per EPA label requirements. Lots harvested before this date may have MRL (Maximum Residue Limit) violations. Critical for food safety compliance and FSMA traceability. [Moved from commodity_lot: The phi_date on commodity_lot is a single scalar that cannot represent the PHI clearance dates from MULTIPLE pesticide applications. The true PHI clearance date is the MAXIMUM phi_clearance_date across all associated PURs for that lot. The lot-level phi_date should be a derived/computed field (max of association phi_clearance_dates), not a stored attribute on the lot itself. The per-application PHI clearance date belongs to the lot_pesticide_exposure association.]',
    `record_status` STRING COMMENT 'Lifecycle status of this lot-application exposure record. PENDING = awaiting compliance review; CONFIRMED = PHI compliance determination finalized; DISPUTED = under review due to data discrepancy; SUPERSEDED = replaced by a corrected record.',
    `review_date` DATE COMMENT 'Date on which this lot-application exposure linkage was reviewed and confirmed by a compliance officer. Part of the regulatory audit trail for PHI compliance sign-off.',
    `reviewed_by` STRING COMMENT 'Name or user ID of the compliance officer or agronomist who reviewed and confirmed this lot-application exposure linkage. Required for regulatory audit trail.',
    CONSTRAINT pk_lot_pesticide_exposure PRIMARY KEY(`lot_pesticide_exposure_id`)
) COMMENT 'This association product represents the PHI Compliance Linkage event between a commodity_lot and a pesticide_use_record. It captures the regulatory determination of whether a specific pesticide application affects a specific commodity lots pre-harvest interval compliance status. Each record links one commodity_lot to one pesticide_use_record and carries the compliance attributes that exist only in the context of this specific lot-application pairing — including the PHI compliance outcome, the area of the lot affected, and the active ingredient exposure details. Required for FSMA Section 204 traceability, EPA pesticide use reporting, and pre-harvest clearance workflows.. Existence Justification: In agricultural operations, a single commodity lot (harvested from a field over a season) is subject to multiple pesticide applications, each generating its own PUR — and a single pesticide application event can affect multiple commodity lots harvested from the same field across different harvest windows. The business actively manages this relationship to determine PHI compliance status for each lot, which is a regulatory obligation under EPA and FSMA rules. This is not an analytical correlation — it is an operational compliance record that agronomists and compliance officers create, query, and audit as part of pre-harvest clearance workflows.';

-- ========= FOREIGN KEYS =========
ALTER TABLE `agriculture_ecm`.`inventory`.`stock_position` ADD CONSTRAINT `fk_inventory_stock_position_bin_location_id` FOREIGN KEY (`bin_location_id`) REFERENCES `agriculture_ecm`.`inventory`.`bin_location`(`bin_location_id`);
ALTER TABLE `agriculture_ecm`.`inventory`.`stock_position` ADD CONSTRAINT `fk_inventory_stock_position_commodity_lot_id` FOREIGN KEY (`commodity_lot_id`) REFERENCES `agriculture_ecm`.`inventory`.`commodity_lot`(`commodity_lot_id`);
ALTER TABLE `agriculture_ecm`.`inventory`.`stock_position` ADD CONSTRAINT `fk_inventory_stock_position_material_master_id` FOREIGN KEY (`material_master_id`) REFERENCES `agriculture_ecm`.`inventory`.`material_master`(`material_master_id`);
ALTER TABLE `agriculture_ecm`.`inventory`.`stock_position` ADD CONSTRAINT `fk_inventory_stock_position_stock_material_master_id` FOREIGN KEY (`stock_material_master_id`) REFERENCES `agriculture_ecm`.`inventory`.`material_master`(`material_master_id`);
